// GENERATED by tools/gen_ja_landmarks.py — Japanese landmark texts,
// keyed by '<citySlug>/<icon>'. Regenerate with the script; do not
// hand-edit individual entries.

const Map<String, (String nameJa, String descJa)> kLandmarkJa = {
  'chengdu/panda': ('成都ジャイアントパンダ繁殖研究基地', '成都ジャイアントパンダ繁殖研究基地は、世界最大のパンダ保護・繁殖センターです。街のシンボルであるパンダが竹林でごろごろと転がる姿を見ようと、毎年何百万人もの人が訪れます。'),
  'chengdu/hotpot': ('四川火鍋', '舌がしびれる四川山椒と真っ赤な辣油でぐつぐつ煮える火鍋は、成都の食文化の中心です。テーブルの真ん中の鍋にそれぞれが具材をくぐらせる、みんなで楽しむ遊びのような食事です。'),
  'chengdu/bianlian': ('変面', '川劇の魔法のような芸「変臉(へんれん)」では、名人が手をひとふりするだけで、色鮮やかな面をまばたきの間に変えてしまいます。その秘密は、師匠から弟子へと代々受け継がれるのみです。'),
  'chengdu/jinli': ('錦里古街', '赤い提灯に照らされる錦里(きんり)は、三国時代にさかのぼる歴史ある商店街です。茶館や影絵芝居、飴で龍を描く職人たちが並び、成都名物のゆったりとした暮らしのリズムを一番よく感じられる場所です。'),
  'nanjing/citywall': ('南京城壁', '明王朝の創始者が都を守るために築かせたこの巨大な城壁は、現存する世界最長の城壁です。品質保証として一つひとつのレンガに職人の名前が刻まれており、今では城壁の上を歩きながら、南京の古い顔と新しい顔を同時に眺めることができます。'),
  'nanjing/plum': ('梅の花', '真冬の雪の中で咲く梅の花は、中国文化で強さと希望の象徴とされ、南京は梅を市の花に選びました。冬の終わりには梅花山の斜面がピンクと白の花の海となり、人々は木々の下を散策して春の訪れを楽しみます。'),
  'nanjing/duck': ('塩水鴨', '南京料理の看板である塩水鴨(えんすいや)は、香辛料入りの塩水に漬けてやさしく茹で、冷たいまま供されます。やわらかな肉と絶妙な塩加減で、鴨はこの街の情熱そのもの。「南京からは一羽の鴨も生きて出られない」という地元のジョークもあるほどです。'),
  'nanjing/bridge': ('南京長江大橋', '1968年に中国人技術者だけの手で完成した南京長江大橋は、道路と鉄道の両方を運ぶ二層構造の巨大な橋です。外国の援助なしに建設されたことから、現代中国の自立の象徴とされ、今も教科書で誇らしく語られています。'),
  'qingdao/beer': ('青島ビール', 'ドイツ統治時代に創業した醸造所により、青島(チンタオ)ビールは中国で世界的に最も有名なビールとなりました。毎年夏の国際ビール祭りで街はお祭り気分に包まれ、屋台で生ビールをビニール袋に入れてストローで飲むのが、青島の一番愛らしい伝統です。'),
  'qingdao/sailing': ('セーリングシティ', '2008年オリンピックのセーリング競技は青島のマリーナで開催され、以来この街は「帆船の都」と呼ばれています。風の吹き抜ける湾、水平線を彩る白い帆、そして海辺の遊歩道を持つ青島は、中国のマリンスポーツの都です。'),
  'qingdao/beach': ('海水浴場', '青島のビーチは、丘に並ぶ赤い屋根のドイツ時代の建物の前に広がり、中国では珍しいヨーロッパの海辺の町のような雰囲気を漂わせます。夏には砂浜が海水浴客でにぎわい、入り江と入り江を結ぶ海岸の道は夕日散歩の定番コースです。'),
  'qingdao/crab': ('海鮮料理', '黄海に面した青島では、新鮮な海の幸が毎日の食卓に並びます。アサリや牡蠣、ウニ、カニの屋台が桟橋を埋め尽くします。地元流の楽しみ方は、その日の獲れたてをシンプルに蒸して、キンキンに冷えた青島ビールと一緒に味わうことです。'),
  'changsha/pepper': ('唐辛子', '湖南料理は、四川のしびれる辛さとは違い、ドライで鋭い辛さで知られ、生や漬け物の唐辛子がほとんどの料理に登場します。長沙で辛さは、湿気の多い気候への昔ながらの知恵。「辛さは怖くない、辛くないことが怖い」と地元の人は冗談を言います。'),
  'changsha/tofu': ('臭豆腐', '発酵した漬け汁に漬けてから揚げる長沙の臭豆腐は、外は真っ黒でカリカリ、中は真っ白でとろけるようです。強烈な匂いにだまされないでください。辛いタレをかけたこの一口は、長沙の夜市で一番長い行列を作る味なのです。'),
  'changsha/fireworks': ('花火', '長沙に隣接する瀏陽(りゅうよう)は、何世紀にもわたり世界の花火の都とされてきました。火薬のふるさとで、この技は代々受け継がれています。湘江のほとりで定期的に開かれる花火大会では、空と川が同時に色鮮やかに染まります。'),
  'changsha/orange': ('橘子洲', '湘江の真ん中に細長く横たわる橘子洲(オレンジ島)は、岸辺を埋めるみかん畑にちなんで名付けられました。若き日にこの川で泳いだ毛沢東は、島について有名な詩を残しました。今日、島の先端では若き毛沢東の巨大な花崗岩の像が川を見つめています。'),
  'zhengzhou/kungfu': ('少林拳', '鄭州近郊の嵩山(すうざん)のふもとに建つ少林寺は、禅宗と少林カンフーが生まれた場所です。約1500年の歴史を持つ僧院の周りの武術学校では、今も何千人もの生徒が夜明けから始まる稽古でこの遺産を受け継いでいます。'),
  'zhengzhou/train': ('鉄道の要衝', '鄭州は、中国の南北と東西を結ぶ幹線鉄道が交差する地点に発展した交通の要衝です。「列車が育てた街」と呼ばれ、今日も国の高速鉄道網で最もにぎわう乗り換えハブのひとつであり続けています。'),
  'zhengzhou/wheat': ('小麦畑', '黄河が潤す河南平原は、中国最大級の小麦の穀倉地帯です。この豊かな大地が北方料理の魂を育みます。手延べ麺も蒸し餃子も焼きたてのパンも、みなこの平原の小麦から生まれるのです。'),
  'zhengzhou/ding': ('青銅鼎', '鄭州とその周辺は、中国最古の王朝のひとつである殷(商)の都が置かれた地で、発掘調査では祭祀に使われた青銅の鼎(てい)が出土しました。鼎は権力と祖先への供物の象徴であり、それゆえこの街は中国文明のゆりかごのひとつに数えられています。'),
  'wuxi/lake': ('太湖', '無錫は中国最大級の淡水湖である太湖のほとりにあり、湖の魚やエビ、水生野菜が地元料理の土台となっています。夕暮れに黿頭渚(げんとうしょ)の岬から眺める湖は、桜の季節にはひときわ幻想的な美しさに包まれます。'),
  'wuxi/peach': ('陽山桃', '無錫の陽山鎮は、蜂蜜のように甘くて驚くほどジューシーな水蜜桃で中国全土に名を馳せています。スプーンで食べられるほどやわらかいこの桃は真夏に熟し、収穫の季節には町がお祭り気分に包まれ、果樹園が観光客に開放されます。'),
  'wuxi/figurine': ('恵山泥人形', '恵山泥人形は、無錫の恵山のふもとで採れるやわらかな黒い粘土から作られる、数百年の歴史を持つ民芸品です。一番人気は、豊かさと喜びを象徴するふっくら頬の子ども「阿福(アフ)」。手描きの鮮やかな彩色が施されたこの人形は、街の定番のお土産です。'),
  'wuxi/boat': ('運河の小舟', '世界最長の人工水路である大運河は、無錫の街の真ん中を流れています。夜、提灯に照らされた清名橋の歴史地区で舟に乗り、白壁と黒瓦の古い家々の間をすべるように進むのが、この街と出会う一番すてきな方法です。'),
  'nanning/tree': ('緑の都', '中国南部の熱帯地域にある南寧は、通りを覆う大きな木々と一年中緑あふれる公園から「緑城」と呼ばれています。ベトナム国境に近いこの街は、中国と東南アジアを結ぶ貿易と文化交流の玄関口です。'),
  'nanning/noodle': ('老友麺', '「老友粉(ラオヨウフェン)」は「古い友の麺」という意味で、発酵タケノコと豆豉、唐辛子で作る酸っぱ辛い南寧の名物です。言い伝えでは、茶館の主人が病気になった旧友を治すために作ったのが始まりで、以来じめじめした日の妙薬とされています。'),
  'nanning/song': ('民謡', '広西のチワン族は、即興の歌を掛け合いながら思いを伝える伝統を何世紀も守り続けています。毎年春の「三月三」の歌垣では若者たちが歌で競い合い、伝説の歌い手・劉三姐(りゅうさんじぇ)はこの伝統で最も愛されるヒロインです。'),
  'nanning/mango': ('南国フルーツ', '熱帯気候の南寧は、マンゴーやリュウガン、ライチ、パパイヤに恵まれた土地で、屋台には一年中新鮮な果物があふれています。暑い夜には、氷を使ったフルーツデザートや搾りたてのジュースが、この街で一番人気の涼のとり方です。'),
  'nanchang/pavilion': ('滕王閣', '贛江(かんこう)のほとりに建つ滕王閣(とうおうかく)は、唐の時代から幾度も壊されては再建されてきた、中国南部で最も名高い三大名楼のひとつです。若き詩人・王勃(おうぼつ)がここで書いた序文は中国文学の傑作となり、この楼閣を不朽のものにしました。'),
  'nanchang/star': ('八一広場', '1927年8月1日に起きた南昌起義は中国人民解放軍の誕生とされ、南昌は「英雄の街」と呼ばれています。軍旗に記された「八一」の文字はこの日付を示し、街の中心広場の名前にもなっています。'),
  'nanchang/porcelain': ('景徳鎮の磁器', '南昌のある江西省には、磁器の世界的な都・景徳鎮があります。皇帝の窯で千年にわたり宮殿のために焼かれたこの「白い金」は、隊商や船に乗ってここから世界へと広まりました。その技は今も若い職人たちの手で生き続けています。'),
  'nanchang/sunset': ('贛江の夜景', '夕方になると贛江の両岸はまったく別の顔を見せます。何百もの建物の壁面が、巨大でシンクロした光のショーに変わるのです。川沿いの公園と、ライトアップされた滕王閣のシルエットは、南昌で一番愛される夜の散歩コースです。'),
  'yinchuan/camel': ('シルクロード', '黄河が潤すオアシスの街・銀川は、シルクロードの隊商が砂漠に踏み出す前に休息をとった西の門のひとつでした。街の郊外では、ピラミッドを思わせる西夏王朝の王陵が、今も砂漠の太陽の下に静かにそびえています。'),
  'yinchuan/grapes': ('賀蘭山のワイン', '賀蘭山の東麓は、豊かな日差しと乾いた空気、石まじりの土壌により、中国で最も優れたワインの産地とされています。ここのブドウ畑から生まれるワインは国際コンクールで賞を重ね、愛好家からは「中国のボルドー」と呼ばれています。'),
  'yinchuan/desert': ('沙坡頭', '銀川に近い沙坡頭(さはとう)では、テンガー砂漠の黄金の砂丘が黄河と出会います。砂漠と大河が隣り合う、世界でも珍しい風景です。砂丘の頂上からのそり滑り、ラクダの隊列での砂漠散策、羊皮のいかだでの川渡りが、この地域の定番の冒険です。'),
  'yinchuan/sheep': ('回族の羊肉料理', '寧夏の回族(ムスリム)料理の主役は羊肉です。クミンをまぶした串焼き、やわらかな茹で羊肉、手延べ麺入りのスープが街の食卓を彩ります。草原の牧場で育つ地元の羊は、そのやわらかさと臭みのない味わいで中国中に知られています。'),
  'lhasa/mountain': ('ポタラ宮', '紅い丘の上にそびえるポタラ宮は、数百の部屋と聖なる霊塔、礼拝堂を持つチベット建築の最高傑作です。かつてダライ・ラマの冬の宮殿だったこの紅白の建物はユネスコ世界遺産に登録されており、ラサのほとんどどこからでも見ることができます。'),
  'lhasa/prayer': ('ジョカン寺（大昭寺）', 'チベット仏教で最も神聖な寺院ジョカン寺(大昭寺)へ、巡礼者たちは時に何キロもの道のりを五体投地しながらやって来ます。寺を囲むバルコル(八廓街)ではマニ車を回しながら歩く巡礼者の流れが一日中絶えず、お香の香りが通りを包みます。'),
  'lhasa/yak': ('ヤク文化', '高原の寒さに強いヤクは、チベットの暮らしを支える大黒柱です。乳からはバターとチーズが、毛からはテントや衣服が作られ、糞は燃料になります。寺院で昼も夜も灯り続ける灯明の燃料さえ、ヤクの乳から作るバターなのです。'),
  'lhasa/tea': ('バター茶', 'ヤクバターと塩、濃く煮出したお茶を撹拌して作るバター茶は、チベットの日常の飲み物です。高地の乾いた寒さの中で、体を温めると同時に栄養も与えてくれます。お客さまの茶碗が空くたびに注ぎ足すのが、チベット流おもてなしの一番やさしいルールです。'),
  'zhuhai/shell': ('珠海漁女像', '海からそびえる岩の上で真珠を空に掲げる「珠海漁女」の像は、珠海のシンボルです。この像は、漁師に恋をして人間の姿になった仙女の地元の伝説から生まれたもので、優雅な立ち姿で海岸通りを歩く人々を迎えています。'),
  'zhuhai/bridge': ('港珠澳大橋', '港珠澳大橋(香港・珠海・マカオ大橋)は全長55キロメートルで世界最長の海上橋であり、橋と人工島、海底トンネルで構成されています。珠江デルタの3つの都市を一本の線で結ぶこの巨大建造物は、現代エンジニアリングの象徴的なプロジェクトのひとつです。'),
  'zhuhai/island': ('百島', '珠海という名は「真珠の海」を意味し、その沿岸には100を超える島々が散らばっています。フェリーで行ける東澳島や外伶仃島などでは、漁村や静かな入り江、海鮮レストランが訪れる人を待っており、どの島もそれぞれのリズムで暮らしています。'),
  'zhuhai/lobster': ('シーフード', '珠江が海と出会う珠海では、その日の獲れたてで食卓が整えられます。ロブスターやシャコ、ホタテ、牡蠣を生け簀から選び、その場で調理してもらえるのです。広東式のやさしい蒸し料理が、素材の新鮮さと自然な甘みを引き立てます。'),
  'yantai/apple': ('煙台リンゴ', '煙台の涼しい海洋性気候と豊かな日差しは、中国で最も有名なリンゴを育てます。赤くてシャキシャキ、蜂蜜の香りがするリンゴは国中に出荷されます。秋には海岸沿いの果樹園が収穫でにぎわい、街はリンゴの香りに包まれます。'),
  'yantai/wine': ('張裕ワイン', '中国初の近代ワイナリーである張裕(チャンユー)は、1892年に煙台で創業した、国内で最も歴史あるワインブランドです。ワイン文化博物館や歴史あるセラー、周辺のワイナリー巡りコースを持つ煙台は、アジアでも数少ない「ワインの街」に数えられています。'),
  'yantai/wave': ('蓬莱海岸', '煙台の蓬莱(ほうらい)の海岸は、中国神話で八仙が海を渡って旅立った場所と伝えられています。海の上に時折現れる蜃気楼がこの海岸に「仙人の郷」の名声をもたらし、断崖の上に建つ歴史ある蓬莱閣が海を見守っています。'),
  'yantai/cherry': ('サクランボ狩り', '煙台は中国有数のサクランボの産地で、涼しい海辺の気候が大粒でジューシー、甘い実を育てるのに理想的です。初夏には果樹園が観光客に開放され、枝からもいだサクランボをその場で味わうのが、この季節一番の甘いお出かけです。'),
  'datong/buddha': ('雲崗石窟', '大同の西の断崖に掘られた雲崗石窟は、北魏時代の何千体もの仏像を今に伝える、中国仏教美術の最高峰のひとつです。手のひらサイズの像もあれば建物ほどの高さの大仏もあり、この石窟群はユネスコ世界遺産に登録されています。'),
  'datong/citywall': ('大同城壁', 'かつて国境の駐屯地だった大同では、明代の城壁が壮麗な城門や隅櫓とともに再建されました。夕暮れに提灯が灯る城壁の上を歩けば、旧市街の屋根並みと新しい大同の灯りをひとつの眺めの中に楽しめます。'),
  'datong/noodle': ('刀削麺', '山西省の誇りである刀削麺(とうしょうめん)では、職人が生地のかたまりを腕に抱え、刃物で削った麺のリボンをそのまま煮えたぎる鍋へと飛ばします。縁が厚く真ん中が薄いこの麺はタレをよく絡め、大同の食卓に欠かせない定番です。'),
  'datong/lantern': ('懸空寺', '大同近くの恒山の断崖に張り付くように建つ懸空寺(けんくうじ)は、細い木の柱に支えられ、まるで宙に浮いているかのようです。約1500年の歴史を持つこの寺は、仏教・道教・儒教をひとつ屋根の下に祀るという点でも唯一無二の存在です。'),
  'baotou/horse': ('草原の馬', '包頭（パオトウ）の名はモンゴル語で「鹿のいる場所」を意味し、街は内モンゴルの草原の縁に築かれています。周囲の草原では馬が今も暮らしの一部で、モンゴルの牧民たちは競馬を催し、馬頭琴（モリンホール）の調べがゲルの間に響きわたります。'),
  'baotou/deer': ('鹿園', '包頭は「鹿の城」と呼ばれ、公園を自由に歩き回る鹿たちがその名を今に伝えています。訪れる人は鹿に手ずから餌をあげることもできます。草原の真ん中で繰り広げられるこの穏やかな光景は、工業都市の意外なほど優しい一面を見せてくれます。'),
  'baotou/factory': ('鋼鉄の街', '包頭は中国最大級の製鉄企業を擁し、国の重工業地図の中で特別な位置を占めています。近隣に鉱床があるおかげで、この街は世界有数のレアアース（希土類元素）の中心地としても知られています。'),
  'baotou/grass': ('草原ツアー', '街から少し足を延ばせば、地平線まで続く大草原にたどり着きます。客人はゲルに泊まり、ミルクティーと羊の丸焼きでもてなされ、夜には焚き火を囲んでモンゴルの歌声が響きます。草原のおもてなしは、ここでは何世紀も続く伝統なのです。'),
  'weifang/kite': ('凧の都', '凧のふるさととされる濰坊(いほう)では、竹の骨組みと手描きの絹によるこの工芸が何世紀も受け継がれてきました。毎年4月に開かれる濰坊国際凧揚げ大会では、世界中から集まった凧が空を色鮮やかな祭典に変えます。'),
  'weifang/woodprint': ('楊家埠木版年画', '濰坊の楊家埠(ようかほ)村は、旧正月に扉に貼られる色鮮やかな木版年画の最も有名な産地のひとつです。門神やふっくらした赤ん坊、豊穣のシンボルが、手彫りの版木から色を重ねて刷られ、その技は代々受け継がれています。'),
  'weifang/dragon': ('龍の凧', '濰坊の空の主役は、龍の頭を持つ巨大なムカデ凧です。何十もの竹の輪が絹の胴体でつながれ、風に波打ちながら何メートルにも伸びていきます。この巨大な凧を揚げるのは、数人がかりのチームの技と力が求められる仕事です。'),
  'weifang/radish': ('濰坊大根', '濰坊の青大根はとても甘くてみずみずしく、地元の人は果物のように皮をむいてスライスして食べます。「濰坊の大根は梨に勝る」という地元のことわざは、この素朴な野菜への誇りを物語っています。お茶の席で客に大根をふるまうのが、この街ならではの心遣いです。'),
  'dezhou/chicken': ('徳州扒鶏', '徳州の扒鶏(パーチー)は、骨から自然に身がほろりと外れるほどやわらかく煮込んだスパイス風味の鶏料理です。大運河と鉄道が交わるにぎやかな立地のおかげで、その名声は全国に広まりました。蜂蜜を塗って揚げ、香辛料入りのスープでじっくり煮込むこの鶏は、かつて皇帝の食卓にも供されました。'),
  'dezhou/sun': ('太陽谷', '太陽エネルギー産業にいち早く投資した徳州は「太陽の街(ソーラーシティ)」の称号を持ち、巨大なソーラーバレーの敷地ではホテルや街灯、住宅までが太陽の力で動いています。この街は、中国の再生可能エネルギーの最も目に見えるショーケースのひとつです。'),
  'dezhou/grapes': ('メロンとブドウ', '黄河平原の肥沃な土壌は、徳州を夏の果物の楽園に変えます。畑はスイカで満ち、棚にはブドウの房がたわわに実ります。道端の屋台で味わうキンキンに冷えたスイカの一切れは、暑い夏の日の定番のひと休みです。'),
  'dezhou/train': ('運河の港', '大運河がにぎわった時代、徳州は穀物を北へ運ぶはしけ船の寄港地でした。今日、運河の役割は鉄道が引き継ぎました。北京・上海線の上にあるこの街は、今も華北の重要な交通の玄関口であり続けています。'),
  'xuzhou/stone': ('漢画像石', '漢王朝の創始者・劉邦のふるさとである徐州は、石に刻まれた歴史のアーカイブです。墓室を飾った漢代の画像石には宴会や戦車、伝説の獣たちが描かれ、二千年前の日常生活をまるで古代の絵物語のように目の前に広げてくれます。'),
  'xuzhou/terracotta': ('漢代兵馬俑', '西安の有名な兵馬俑より小ぶりですが、漢代の兵馬俑がここで楚王の墓を守る姿で発見されました。膝ほどの高さの兵士たちは整然と列をなし、ミニチュアサイズながらその厳粛な佇まいは、死後もなお仕えつづける軍隊の姿を物語っています。'),
  'xuzhou/lake': ('雲龍湖', '「雲の龍」にちなんで名づけられた雲龍湖は、丘に囲まれた広々とした水鏡で、街の緑の肺と呼ばれています。湖畔の遊歩道や茶館、寺院のある丘とともに、朝の運動から夕方の散歩まで、徐州の人々は一日中ここに集まってきます。'),
  'xuzhou/skewer': ('バーベキュー文化', '徐州は「中国のバーベキューの都」を誇りにしており、炭火で焼かれる羊肉の串の煙が夜遅くまで街に漂います。小さな炭火コンロがそのままテーブルに運ばれ、自分の串は自分で焼くのがこの土地の流儀。友人たちと夜更けまで続く、にぎやかで陽気な食卓の文化です。'),
  'zhenjiang/vinegar': ('鎮江香酢', '鎮江の黒米酢(香酢)は、もち米を長い時間をかけてじっくり発酵させて作られます。まろやかな酸味とほのかな甘みを持つ、中国料理で最も有名な酢です。餃子の食卓には欠かせない相棒で、地元の言い伝えによれば、鎮江の街には酢の香りが漂っているのだそうです。'),
  'zhenjiang/temple': ('金山寺', '長江のほとりの金山寺は、中国で最も愛される民話「白蛇伝」のクライマックスの舞台です。蛇の精・白素貞(はくそてい)が愛のために寺を大水で沈めようとした物語は、ここで繰り広げられました。丘の頂に建つ塔は、川と街を見渡しています。'),
  'zhenjiang/pot': ('鍋蓋麺', '鎮江の鍋蓋麺(グオガイミエン)では、煮えたぎる大鍋の中に小さな木の蓋を浮かべます。水面に浮かぶ蓋が吹きこぼれを防ぎ、麺をちょうどよい歯ごたえに茹で上げるのです。細い麺は地元の酢と醤油ベースのスープに合わせられます。これがこの街の朝の定番なのです。'),
  'zhenjiang/bridge': ('長江沿岸', '鎮江は、長江と大運河が交わる要衝に築かれた古い港町です。川に面した金山・北固山・焦山の三つの丘は、塔や寺院、散策路のある公園を連ね、川辺を緑豊かな文化の帯へと変えています。'),
  'jiaxing/zongzi': ('粽', '竹の葉に包んで蒸すもち米のちまき「粽子（ゾンズ）」の都といえば嘉興です。端午節（ドラゴンボート祭り）を象徴するこの食べ物は、豚肉入り、あんこ入り、塩漬け卵黄入りなどの種類で一年中売られています。熱々のちまきを開くひとときは、竹の葉の香りから始まる小さな儀式です。'),
  'jiaxing/boat': ('南湖の遊覧船', '1921年、上海を離れざるを得なくなった中国共産党の第一回大会は、嘉興の南湖に浮かぶ一艘の船の上で締めくくられました。「紅船」と呼ばれるその船の複製が今も湖に浮かび、霧に包まれた水面、柳、島の東屋が、訪問に静かな歴史の趣を添えています。'),
  'jiaxing/silk': ('シルクの里', '江南の桑畑と養蚕の文化は、何世紀にもわたって嘉興の水郷の町々を支えてきました。繭から引き出された糸はここで布団や織物、刺繍へと姿を変えます。絹のやわらかさは、水に恵まれた温暖な気候がこの地に授けた、畑から衣服にまで届く贈り物なのです。'),
  'jiaxing/canal': ('烏鎮', '嘉興の近郊にある烏鎮は、石橋、黒瓦の家々、運河へと降りる石段を持つ、江南水郷の中でもとりわけ優雅な町です。夕暮れに提灯がともると水面は赤く染まり、藍染めや影絵芝居といった昔ながらの工芸が、狭い路地に今も息づいています。'),
  'lishui/mountains': ('緑の峰々', '麗水は浙江省でもっとも山深い一角で、谷は霧に、尾根は竹と松の森に包まれています。斜面に築かれた石造りの村々と雲に触れる棚田が、にぎやかな沿海の省の喧騒から遠く離れた、ゆったりとした緑の中国を秘めています。'),
  'lishui/camera': ('写真の聖地', '夜明けの霧に満たされた谷、棚田に現れる農夫たち、光とともに姿を変える雲海が、麗水を写真家たちの聖地に変えました。この街は国際的な写真イベントで知られており、もっとも有名な一枚は、日の出に水を張った棚田が黄金色に輝く瞬間をとらえたものです。'),
  'lishui/mushroom': ('キノコの里', '麗水の慶元県はキノコ栽培の発祥の地とされ、シイタケを原木で育てる方法は何世紀も前にこの山々で生み出されました。今でも村の市場には干しシイタケの香りが漂い、地元の台所は採れたてのキノコで作るスープや煮込み料理を自慢にしています。'),
  'lishui/raft': ('川下り', '甌江（おうこう）は麗水の緑の渓谷の間を曲がりくねって流れ、その澄んだ水を竹のいかだで下るのがこの地方ならではの楽しみです。船頭が長い竿で舵を取るあいだ、岸辺には漁村や霧の丘、中国の水墨画そのままの風景が次々と流れていきます。'),
  'anqing/opera': ('黄梅戯', '黄梅戯(こうばいぎ)は、安慶周辺の茶摘み歌から生まれ、中国で最も愛される地方劇のひとつへと育ちました。素朴で流れるような旋律と、日常の言葉で語られる恋物語は何世代にもわたって口ずさまれ、安慶は今もこの芸術の都とされています。'),
  'anqing/pagoda': ('振風塔', '長江のほとりにそびえる振風塔(しんぷうとう)は、何世紀にもわたり川を行く船人たちの灯台の役目を果たし、「長江第一の塔」と呼ばれました。明代に建てられたこの八角形の塔は、各層を登る人々に、大きく蛇行する川の雄大な眺めを贈ってくれます。'),
  'anqing/tea': ('岳西茶', '安慶の背後にそびえる大別山の霧深く涼しい斜面は、香り高い緑茶の理想的な茶園です。岳西県で春に手摘みされる若葉は、軽やかで花のような味わいのお茶になります。山あいの村々では、茶摘みは今も季節最大のイベントです。'),
  'anqing/sail': ('安慶', '「安らかな祝い」を意味する名を持つ安慶は、安徽省の長江に開かれた歴史的な港の玄関口で、省の名前の「安」の字はこの街に由来します。川沿いの埠頭や古い町並みは、にぎわった港町時代の面影を今も残しています。'),
  'ganzhou/orange': ('贛南ネーブルオレンジ', '贛州（かんしゅう）の赤い土と温暖な南方の気候は、中国でもっとも甘いネーブルオレンジと称される贛南オレンジを育てます。収穫の季節には丘がオレンジ色に染まり、みずみずしく種のないこの果実は、街の名を国じゅうに広める誇りの源となっています。'),
  'ganzhou/house': ('客家円楼', '北方から移り住んだ客家（ハッカ）の人々は、贛州の山あいの村に防御のための城塞住宅を築きました。分厚い壁の内側では、数十の家族がひとつ屋根の下に暮らします。中には共用の中庭や祖先を祀る堂があり、何百年も受け継がれてきた固い結束の文化が息づいています。'),
  'ganzhou/pavilion': ('郁孤台', '鬱孤台（うつこだい）は、章江と貢江が合流して贛江が生まれる地点を見下ろしています。宋代の詩人たちの詩に詠まれたこの木造の楼閣では、川の景色と千年の詩の伝統がひとつに溶け合います。夕暮れの光の中、ここは街でいちばん物思いを誘う場所です。'),
  'ganzhou/star': ('長征', '1934年、紅軍は歴史に「長征」として刻まれる壮大な撤退の旅を、贛州の于都県から始めました。夜通し川を渡った兵士たちの物語は、ここで記念碑や博物館によって語り継がれています。この街は、中国近現代史の転換点のひとつのスタートラインなのです。'),
  'putian/shrine': ('媽祖廟', '船乗りたちの守り神である女神・媽祖（まそ）は莆田（ほでん）に生まれました。その総本山は湄州島にそびえ、世界に数千ある媽祖廟の源とされています。媽祖信仰とその風習はユネスコの無形文化遺産に登録されており、祭りの日には島じゅうが線香の煙と巡礼者で満たされます。'),
  'putian/lychee': ('ライチの果樹園', '莆田は「ライチの街」とも呼ばれ、樹齢数百年のライチの木が今も実をつけ、街路に木陰を作っています。夏の収穫期に皮が赤く色づくこの甘い果実は、古典詩にも詠まれた南国の贅沢品。枝からもいだばかりのライチを味わうのは、莆田の夏の何よりの楽しみです。'),
  'putian/shoe': ('靴の都', '莆田は世界のスニーカー生産を支える静かな巨人のひとつで、その工房と工場は大手ブランドのために何百万足もの靴を作っています。ここでは靴づくりが家業のように受け継がれており、型職人から縫製職人まで連なる職人の鎖が、世界のスポーツファッションの見えない台所となっています。'),
  'putian/wave': ('湄洲島', 'フェリーで渡る湄州島は、黄金色の砂浜、岩がちな入り江、そして媽祖廟の祭礼で知られています。女神の誕生日の祝いには島じゅうが太鼓の音と行列でにぎわい、それ以外の日は、海風の吹く静かな巡礼と保養の地となります。'),
  'mudanjiang/snow': ('中国雪郷', '牡丹江近くの「中国雪郷」は、国内で最も雪深い村のひとつです。屋根の上にふくらむ分厚い雪のクッションが、家々をおとぎ話の山小屋に変えてしまいます。夕暮れに赤い提灯が灯ると、雪に覆われた小道は温かな光に照らし出されます。'),
  'mudanjiang/lake': ('鏡泊湖', '鏡泊湖(きょうはくこ)は、はるか昔の火山の噴火が川をせき止めてできた、中国最大級の火山堰止湖です。湖の水は吊水楼(ちょうすいろう)の滝から流れ落ち、夏の勇敢な飛び込みダイバーと、凍りついた冬の絶景がこの地域の名物です。'),
  'mudanjiang/tiger': ('東北虎林園', '牡丹江地域の横道河子(おうどうかし)は、世界最大のネコ科動物であるシベリアトラ(アムールトラ)の保護・繁殖センターとして世界有数の存在です。広い森の敷地を歩き回るトラを保護された見学ルートから観察でき、この希少種の未来を守る取り組みの中心地となっています。'),
  'mudanjiang/ski': ('スキーシーズン', '中国の豪雪地帯にある牡丹江の冬は長く、乾いた雪がたっぷりと降ります。街を囲む森の丘は、毎シーズンスキーヤーでにぎわいます。雪郷への旅と組み合わせたスキーコースが、この地域を中国東北部の冬季観光の中心地のひとつにしています。'),
  'changzhou/dino': ('中華恐竜園', '常州恐竜園は、化石博物館と遊園地をひとつにした中国で最も有名な恐竜テーマパークで、「中国のジュラシック・パーク」と親しみを込めて呼ばれています。巨大な恐竜の模型やウォーターライド、ジェットコースターがそろうこのパークは、家族連れにとって街いちばんの人気スポットです。'),
  'changzhou/pagoda': ('天寧寺塔', '市の中心にある天寧寺の高さ153メートルの塔は、世界一高い仏塔とされています。千年を超える歴史を持つ寺の境内にそびえるこの塔の最上階からは、常州の街全体と大運河の曲線を足元に一望できます。'),
  'changzhou/comb': ('常州梳篦', '常州の櫛(くし)は、ツゲやコクタンなどの銘木から何十もの手作業の工程を経て作られる、何世紀も前にさかのぼる工芸品です。かつては宮廷への贈り物にもなったこの櫛は、繊細な彫刻と手描きの絵柄で、今もこの街で一番優雅なお土産です。'),
  'changzhou/canal': ('京杭大運河', '大運河は何世紀にもわたり常州の中を流れ、街はこの水路がもたらした交易と織物業で豊かになりました。夜には運河沿いの古い町並みが提灯に照らされ、石造りの船着き場に沿って歩くのが、この街の一番の定番の楽しみです。'),
  'shaoxing/wine': ('紹興酒', '紹興の琥珀色に輝く黄酒(紹興酒)は、地元の鑑湖の水で醸されます。食卓のお酒としても、中国料理に欠かせない調味料としても愛されています。娘が生まれたときに甕(かめ)を土に埋め、嫁ぐ日に開けるという習わしは、この街で最も優雅な伝統のひとつです。'),
  'shaoxing/bridge': ('石橋', '運河が網の目のように走る紹興では、水路は通りと同じくらいにぎわい、何百ものアーチ型の石橋を持つこの街は「橋の博物館」と呼ばれています。何世紀も立ち続ける橋もあり、苔むした石のアーチは、その下をすべる舟に今も影を落としています。'),
  'shaoxing/pen': ('書道の聖地', '書の最高の名人とされる王羲之(おうぎし)は、傑作「蘭亭序」を紹興の竹林での宴で書き上げました。小川に杯を浮かべて詩を詠む「曲水流觴(きょくすいりゅうしょう)」の風習はその日から伝わるもので、蘭亭は今も書を愛する人々の聖地です。'),
  'shaoxing/boat': ('烏篷船', '紹興の黒い日よけを張った烏篷船(うほうせん)では、船頭が足で櫂を漕ぎながら手で舵を取ります。これは何世代も受け継がれてきた独特の技です。狭い運河を石橋の下をくぐって進むこの舟は、この街が育てた文豪・魯迅の子ども時代の思い出にも大切に登場します。'),
  'bengbu/shell': ('真珠の港', '蚌埠(ボンブ)という名は「カキ貝の埠頭」を意味し、淮河(わいが)のこの岸辺はかつて淡水真珠を採る人々で有名でした。真珠は今もこの街のシンボルで、広場の彫像から市の紋章まで、いたるところで目にすることができます。'),
  'bengbu/train': ('蚌埠駅', '蚌埠は、天津と浦口を結ぶ鉄道が淮河を渡る地点で、小さな町から大きな都市へと成長しました。南北幹線のこの玄関口は、安徽省北部を国の主要交通網につなぐ役割を今も果たし続けています。'),
  'bengbu/river': ('淮河', '淮河は、中国を北と南に分ける自然の境界線とされています。この線の北では小麦が、南では米が育てられ、冬の集中暖房も北側の家にはあり、南側にはありません。蚌埠はちょうどこの境界線の上、ふたつの気候とふたつの食文化のあいだで暮らしているのです。'),
  'bengbu/blossom': ('春の祭典', '春になると淮河沿いの公園はいっせいに花開き、蚌埠の人々は週末を川辺でのピクニックや花祭りで過ごします。湖のほとりの張公山公園は、桜と桃の花の季節には街で一番にぎわう待ち合わせスポットになります。'),
  'jiujiang/mountain': ('廬山', '長江と鄱陽湖(はようこ)の間にそびえる廬山(ろざん)は、霧に包まれた峰々と滝、涼しい高原を持つ、中国で最も詩情豊かな山であり、ユネスコ世界遺産に登録されています。李白が滝を詠んだ詩から、山腹の牯嶺(これい)の町に並ぶ石造りの別荘まで、どの一角にも物語が息づいています。'),
  'jiujiang/tea': ('雲霧茶', '廬山の雲に覆われた斜面で育つ雲霧茶(うんむちゃ)は、中国の名高い緑茶のひとつです。山の湿気と霧を通したやわらかな日差しが、茶葉にフレッシュで甘い香りを与えます。春一番の新芽は手摘みされ、最も貴重な収穫とされています。'),
  'jiujiang/lake': ('鄱陽湖', '中国最大の淡水湖である鄱陽湖は、九江のすぐそばで長江に注いでいます。その水は季節ごとに満ちたり引いたりし、冬に姿を現す湿った草原には、希少なソデグロヅルを含む何万羽もの渡り鳥が集まります。'),
  'jiujiang/scroll': ('詩の街', '長江のほとりのこの古い港は、中国詩の偉大な名人たちを迎えてきました。白居易(はくきょい)は、川で耳にした調べに心を動かされ、名作「琵琶行」をここで書いたのです。廬山の懐に抱かれた九江は、詩の中で最も多く名前を呼ばれた川の玄関口のひとつです。'),
  'quanzhou/ship': ('海のシルクロード', '中世に「ザイトン」の名で知られた泉州は、海のシルクロード最大の港でした。マルコ・ポーロはここを世界で最もにぎわう港のひとつと記しています。モスクと寺院と教会が並び立つこの街は、そのコスモポリタンな遺産によってユネスコ世界遺産に登録されています。'),
  'quanzhou/mosque': ('清浄寺', '1009年にアラブ商人によって建てられた清浄寺(せいじょうじ)は、中国に現存する最古のモスクのひとつです。中東建築に着想を得た花崗岩の門と石の壁は、海のシルクロードの時代に泉州の港がいかに多くの信仰を受け入れたコスモポリタンな街だったかを物語っています。'),
  'quanzhou/puppet': ('泉州提線木偶戯', '泉州の糸操り人形芝居では、名人が何十本もの細い糸を同時に操り、木の人形にまるで命を吹き込むかのようです。人形は字を書いたり、剣を構えて戦ったりもできます。千年の歴史を持つこの伝統は、寺院の縁日や祭りの舞台の主役であり続けています。'),
  'quanzhou/tea': ('鉄観音', '泉州の山あいにある安渓県は、世界で最も有名な烏龍茶「鉄観音」のふるさとです。半発酵の茶葉は蘭の花を思わせる香りとともに開き、小さな茶杯で味わう工夫茶(ゴンフーチャ)の茶席は、ここでは日常の暮らしそのものなのです。'),
  'shanghai/pearl': ('東方明珠電視塔', '浦東（プードン）の陸家嘴地区にそびえるピンク色の球体を持つタワーは、現代上海を象徴するシルエットです。ガラス床の展望台からは黄浦江と対岸の外灘（バンド）が足元に広がり、夜には色とりどりの光が川面にきらめきます。'),
  'shanghai/bund': ('外灘', '黄浦江沿いに並ぶ歴史ある銀行やホテルの建物は、上海が世界の港として栄えた時代の華やぎを今に伝えています。夕暮れの散歩では、片側に石柱の並ぶ古い商館が、もう片側には浦東の摩天楼が輝き、二つの世紀がひと目で出会います。'),
  'shanghai/garden': ('豫園', '明代に造られたこの古典庭園（豫園）は、築山や池、ジグザグの橋を備えた、都会の真ん中のオアシスです。周囲の市場は茶館や軽食の屋台でにぎわい、龍の飾りを頂く塀の内側には、江南庭園芸術の粋が息づいています。'),
  'shanghai/xlb': ('小籠包', '薄い皮の中に熱々のスープを閉じ込めた小籠包（ショーロンポー）は、上海料理の傑作です。まず皮の端を少しかじってスープを味わい、それから生姜入りの黒酢につけていただきます。竹のせいろから立ちのぼる湯気が、毎朝この街の路地を包みます。'),
  'hangzhou/lake': ('西湖', '柳と小島、アーチ橋の連なる西湖は、中国の詩に最も多くうたわれた風景であり、ユネスコ世界遺産にも登録されています。蘇堤と白堤を散策するのは何世紀も続く習わしで、断橋は「白蛇伝」の恋人たちが出会った場所として語り継がれています。'),
  'hangzhou/tea': ('龍井茶', '湖を囲む山の斜面で育つ「龍井（ロンジン）」茶は、中国で最も有名な緑茶です。平たい茶葉は今も熱い釜の中で手作業により形づくられ、早春の一番摘みが最も珍重されます。村の茶館で味わう一杯の龍井茶は、杭州の心そのものを届けてくれます。'),
  'hangzhou/temple': ('霊隠寺', '「魂の隠れ家」を意味する霊隠寺（りんいんじ）は、中国最古級の仏教寺院のひとつです。向かいの飛来峰の岩壁には、何世紀にもわたって数百体もの仏像が刻まれてきました。線香の煙と松の木陰の中を歩けば、都会の喧騒を忘れさせてくれます。'),
  'hangzhou/silk': ('シルクシティ', '杭州の絹は千年以上にわたって織り継がれ、この街はシルクロードの東の果ての豊かさの象徴でした。今日ではシルク市場で生地やスカーフ、刺繍が取り引きされ、シルク博物館は繭から織機までの旅路を伝えています。柔らかな手触りの杭州シルクは、今も最も上品な贈り物です。'),
  'chongqing/hongya': ('洪崖洞', '崖にしがみつくように建つ伝統的な高床式の楼閣群、洪崖洞（ホンヤードン）は、山の街の古い建築を今に伝えています。幾層にも重なる建物が夜に灯りをともすと、嘉陵江のほとりでおとぎ話のように輝き、細い路地には地元の軽食や工芸品の店があふれています。'),
  'chongqing/hotpot': ('重慶火鍋', '真っ赤な辛い油と舌をしびれさせる花椒（ホアジャオ）で煮え立つ火鍋は、重慶の燃えるような魂です。言い伝えでは、川の船着き場で働く荷担ぎたちの大鍋から生まれたのだとか。テーブル中央の九つに仕切られた鍋にひと口ずつくぐらせるうちに、友との長いおしゃべりが弾みます。'),
  'chongqing/monorail': ('重慶モノレール', '丘の上に築かれた重慶では、モノレールが谷を飛び越え、ある駅ではなんと列車がマンションの中を通り抜けます。この光景は街を代表する名物になりました。坂道とエレベーターと橋を駆使する「山の都」は、平面的な地図の常識に挑み続けています。'),
  'chongqing/river': ('長江三峡', 'この街は長江と嘉陵江が合流する地点にそびえ、朝天門の船着き場からは三峡クルーズが出航します。船が切り立った断崖の間をすべるように進むと、中国最大の川が数千年運んできた交易と詩の歴史が、目の前を流れていくかのようです。'),
  'dalian/square': ('星海広場', '海に向かって開ける星海広場は世界最大級の都市広場で、その名は「星の海」に由来します。広々とした芝生の上には凧が舞い、夕方には海沿いの道を自転車が走り抜けます。祭りの季節になると、広場はコンサートやショーで大いににぎわいます。'),
  'dalian/beach': ('大連のビーチ', '岩場の入り江ときれいなビーチ、涼しい夏を持つ大連は、中国北方で人気のリゾート海岸です。海岸線を縫うように走る浜海路は、断崖と入り江の間に息をのむような眺めを見せてくれます。暑さに疲れた北方の人々は、夏になるとこの海で一息つくのです。'),
  'dalian/football': ('サッカーの街', '大連は中国の「サッカーのゆりかご」と呼ばれ、国内リーグを席巻した名門クラブや数多くの代表選手がこの街から巣立ちました。海辺の公園でボールを追いかける子どもたちが伝統を受け継ぎ、試合の日には街全体がひとつの熱いスタンドに変わります。'),
  'dalian/seafood': ('大連海鮮', '冷たく澄んだ黄海は、大連の食卓にホタテ、エビ、ウニ、ナマコを届けてくれます。海辺のレストランでは、生けすから選んだ魚介がわずか数分で蒸し上げられます。そして焼きイカの香ばしい匂いは、夜市に欠かせない名物です。'),
  'shenyang/palace': ('瀋陽故宮', '清王朝の創始者たちが築いた瀋陽故宮（ムクデン宮殿）は、都が北京に移る前の最初の王宮でした。紫禁城の「小さな兄弟」と呼ばれることもありますが、満洲様式を伝える八角形の殿堂など独自の個性を持ち、今日ではユネスコ世界遺産の博物館となっています。'),
  'shenyang/tomb': ('清の陵墓', '街を囲む東陵と北陵は、清王朝を築いた歴代皇帝の壮大な陵墓で、ユネスコ世界遺産に登録されています。石の動物像が並ぶ神道が樹齢を重ねた松林の中を貫き、秋になると陵墓の公園は一面の黄金色に染まります。'),
  'shenyang/factory': ('工業の揺りかご', '中国の重工業の多くは瀋陽で生まれ、巨大な機械工場が立ち並ぶ姿から「東方のルール地方」と呼ばれました。鉄西区の古い工場は今、博物館やアートスペースへと生まれ変わりつつありますが、旋盤の前で働いた世代の誇りは、今もこの街の空気に息づいています。'),
  'shenyang/dumpling': ('老辺餃子', '清の時代から作られてきた老辺餃子（ラオビエンぎょうざ）は、北方の食卓を代表する看板料理です。餡をあらかじめ加熱して旨味を含ませる製法が、比類のない柔らかさを生み出します。老舗の店で味わうひとせいろの餃子は、瀋陽への公式な歓迎のあいさつのようなものです。'),
  'hefei/judge': ('包公祠', '宋代の伝説的な名裁判官・包拯（ほうじょう）は合肥で生まれ、人々からは「包青天」、すなわち曇りなき青空と呼ばれています。賄賂に屈しないその公正さは、京劇やテレビドラマの題材になってきました。湖のほとりにある記念公園は、清廉さに捧げられた神殿のようです。'),
  'hefei/science': ('科学都市', '合肥は、中国を代表する大学や研究所が集まる科学都市です。核融合実験から量子研究まで幅広いプロジェクトがここで進められており、キャンパスやサイエンスパークが街に若々しく好奇心に満ちた空気を与えています。'),
  'hefei/lake': ('巣湖', '巣湖（そうこ）は中国五大淡水湖のひとつで、合肥のすぐ南に広がっています。この湖でとれる白魚、白エビ、カニは「三つの宝」と呼ばれています。湖畔の町では漁船や湖を望む茶館が、ゆったりとした暮らしのリズムを奏でています。'),
  'hefei/cake': ('廬州焼餅', '合肥の古い名は廬州（ろしゅう）といい、甘い餡入りのごま焼き菓子はその名を受け継ぐ昔ながらのお菓子です。香ばしく炒ったごまの香りが、さくさくの皮の下の柔らかな餡と溶け合います。お祝いの季節には、贈答箱の一番目立つ場所にいつもこのお菓子が収められます。'),
  'foshan/wingchun': ('詠春拳', '武術・詠春拳（えいしゅんけん）は仏山で成熟しました。伝説の達人イップ・マン（葉問）はここで腕を磨き、弟子のブルース・リーを通じてその遺産は世界へ広がりました。街の記念館や武術学校が伝統を守り、朝の公園で型の稽古をする達人の姿は日常の風景です。'),
  'foshan/lion': ('南獅', '仏山は南派獅子舞の都であり、名高い民衆の英雄・黄飛鴻（ウォン・フェイホン）もこの地の出身です。祭りでは色鮮やかな獅子たちが太鼓の響きに合わせて高い柱の上を跳び回ります。獅子頭づくりは、世代から世代へ受け継がれる繊細な手仕事なのです。'),
  'foshan/ceramic': ('石湾陶器', '石湾（せきわん）の陶窯の火は何世紀も絶えることなく燃え続けており、南風古竈は中国で今も使われている最古級の薪窯のひとつです。生き生きとした表情の人形や釉薬をかけた屋根飾りで知られる石湾焼は、広東の寺院の屋根までも彩っています。'),
  'foshan/opera': ('広東オペラ', '華南で最も愛される舞台芸術・粤劇（広東オペラ）は、この土地で花開きました。かつて劇団は「紅船」と呼ばれる船で珠江デルタを巡り、村から村へと舞台を披露していました。華やかな衣装、アクロバット、広東語の歌声は、今も劇場を満たしています。'),
  'guiyang/pavilion': ('甲秀楼', '南明河の中の岩の上に建つ三層の甲秀楼（こうしゅうろう）は、明代以来この街のシンボルです。その名は「第一の秀才」を意味し、街から科挙に優れた学者が育つようにとの願いを込めて建てられました。夜、楼の灯りが川面に映るとき、貴陽で最も優美な眺めが生まれます。'),
  'guiyang/sourfish': ('酸湯魚', '酸湯魚（サンタンユー）は貴州を代表する料理で、そのルーツはミャオ族の発酵の伝統にあります。トマトと米の発酵で酸味をつけた真っ赤なスープの中で、淡水魚をじっくり煮込みます。酸味と辛味と香りの踊るような調和は、山がちな南方の気候にぴったりなのです。'),
  'guiyang/waterfall': ('黄果樹瀑布', '貴陽から足を延ばせる黄果樹（こうかじゅ）瀑布は、アジア最大級の滝です。轟音を立てる水のカーテンの裏側にある「水簾洞」を歩いて通り抜けることができ、飛沫は陽の光に虹を描きます。雨季には、滝の轟きが谷を伝って何キロも先まで届きます。'),
  'guiyang/miao': ('ミャオ族文化', '貴州の山あいの村々は、銀の頭飾りで名高いミャオ族のふるさとです。祭りになると若い娘たちは手作りの銀冠と刺繍の衣装を身にまとい、蘆笙（ろしょう）という竹笛の調べに合わせて輪になって踊ります。ろうけつ染めと刺繍は、母から娘へ受け継がれる言葉なのです。'),
  'changchun/film': ('映画の街', '長春映画製作所は、新中国の映画が生まれた場所であり、幾世代にもわたって国の名作映画がここで撮影されました。そのためこの街は「東方のハリウッド」と呼ばれています。古い撮影所は今では映画をテーマにした公園に生まれ変わり、映画祭の伝統は続いています。'),
  'changchun/car': ('自動車の街', '中国初の国産トラックと初の国産乗用車は長春の工場から生まれ、国家元首を乗せる紅旗（ホンチー）のリムジンも今なおここで造られています。「自動車の街」の名は伊達ではありません。工場、博物館、モーターショーが織りなす自動車文化こそ、この街のアイデンティティです。'),
  'changchun/palace': ('満州国皇宮', '中国最後の皇帝・溥儀（ふぎ）は、満洲国時代にこの宮殿で傀儡の君主として暮らしました。現在は博物館となっているこの建物は、堂々とした広間の裏にあった監視と孤独の日々を物語っています。宮殿は、激動の二十世紀の歴史をのぞく静かな窓なのです。'),
  'changchun/snow': ('冬の雪景色', '長く真っ白な長春の冬は、街を雪の祭典に変えます。夜には氷の彫刻が色とりどりの光に輝き、森に囲まれた浄月潭（じょうげつたん）の湖はスキーヤーやそり遊びの人々を迎えます。寒さにもかかわらず、ここでは冬こそ一年で最も陽気な季節なのです。'),
  'xining/lake': ('青海湖', '青海湖は中国最大の湖で、高原の真ん中にターコイズブルーの海のように広がっています。夏には湖岸が黄金色の菜の花畑に包まれ、渡り鳥たちが島々に降り立ちます。湖を一周するサイクリングは、旅人たちに最も愛される高原の冒険です。'),
  'xining/monastery': ('タール寺', 'タール寺（クンブム）はチベット仏教最大級の僧院で、ゲルク派の開祖ツォンカパの生誕の地に建っています。ヤクバターで作られた色鮮やかな彫刻、壁画、布の貼り絵は「三つの芸術」として名高いものです。境内では、巡礼者たちの回すマニ車が絶えることなく回り続けています。'),
  'xining/flower': ('菜の花', '七月になると、青海の高原は地平線の彼方まで黄金色の菜の花に覆われます。とりわけ湖のほとりや山裾は、幾千もの黄色の濃淡に波打ちます。涼しい高原の空気の中でのこの絶景は、毎年写真家や新婚旅行のカップルを引き寄せてやみません。'),
  'xining/lamb': ('ヤクと羊肉', '西寧の食卓は、回族とチベット族の料理が出会う場所です。手延べ麺は湯気の立つ丼で供され、羊肉の串焼きは炭火の上でぱちぱちと音を立てます。ヤクのヨーグルトとバター茶は高原の日常の味わいです。夜になると、市場はスパイスの香りに包まれます。'),
  'guilin/karst': ('漓江のカルスト地形', '霧の中からそびえ立つ石灰岩の峰々の間を、漓江（りこう）が曲がりくねって流れます。この風景はまさに20元紙幣に描かれた眺めです。桂林から陽朔へと下る船、竹のいかだ、鵜飼いの漁師たちが、生きた中国絵画を描き出します。'),
  'guilin/elephant': ('象鼻山', '漓江に鼻を浸す象の姿に似たこの岩山（象鼻山）は、桂林で最も愛されるシンボルです。鼻と胴の間のアーチが水面に映ると満月のように見えることから、「水月洞」と呼ばれています。詩人たちは何世紀にもわたり、この風景を詩に詠んできました。'),
  'guilin/terrace': ('龍脊棚田', '山の尾根を一段一段包み込む龍脊（ロンジー）棚田、すなわち「龍の背骨」は、チワン族とヤオ族の何世紀にもわたる営みの結晶です。春には水を張った棚田が鏡のように輝き、秋には黄金色に染まります。高みにある木造の村々では、伝統的な暮らしが今も続いています。'),
  'guilin/osmanthus': ('キンモクセイ', '桂林の名は「桂（キンモクセイ）の林」を意味し、秋になると街はこの小さな花の甘い香りに包まれます。キンモクセイのお茶、お酒、お菓子は地元の名物の筆頭です。川沿いの香り立つ木々の下を散歩するのは、この季節いちばん美しい習わしです。'),
  'wenzhou/merchant': ('温州商人の精神', '温州の人々は中国で最も起業家精神に富む人々として知られ、家族と同郷のネットワークを通じてヨーロッパからアメリカ大陸まで交易の橋を架けてきました。改革開放の時代に民間ビジネスの先駆けとなったこの街には、小さな工房から世界市場へと羽ばたいた物語があふれています。'),
  'wenzhou/shoe': ('靴と皮革産業', '温州は中国の靴と革製品の都とされ、世界の革靴の大きな部分がこの工場都市から送り出されています。ライターから眼鏡まで小さな商品づくりにも長けたこの街は、「どの家もひとつの工房」だった時代の職人魂を今も受け継いでいます。'),
  'wenzhou/mountain': ('雁蕩山', '滝と鋭い峰々で名高い雁蕩山（がんとうざん）は、「海上の名山第一」とたたえられています。大龍湫（だいりゅうしゅう）の滝は轟音とともに断崖を流れ落ち、夕暮れにはいくつかの峰のシルエットが姿を変えるように見えます。この山は地質学的な価値から保護されたジオパークでもあります。'),
  'wenzhou/seafood': ('海鮮料理', '東シナ海に開けた温州の料理はあっさりとして新鮮で、イカ、ホタテ、魚が日々の食卓の中心です。地元の甌菜（おうさい）は、海の幸そのものの味わいを主役にします。手でたたいて作る魚のつみれスープは、この街でいちばん愛される屋台の味です。'),
  'tangshan/memorial': ('唐山地震記念碑', '1976年の大地震は唐山の街を壊滅させました。現在の追悼公園では、犠牲者の名前が長い御影石の壁に刻まれています。静かな池のほとりでは毎年追悼式典が営まれます。再建された街は、たくましさと再生の象徴となりました。'),
  'tangshan/coal': ('唐山炭鉱', '中国初の近代的な炭鉱と最初期の鉄道のひとつは唐山で開かれ、国内初の蒸気機関車もここで造られました。そのためこの街は中国産業のゆりかごと呼ばれています。炭鉱と鉄鋼の文化は、今日に至るまで街のアイデンティティに深く織り込まれています。'),
  'tangshan/ceramic': ('唐山陶磁器', '唐山は「北方の磁都」と呼ばれ、とりわけボーンチャイナの生産で名高い街です。薄く光を透かす白い食器は、中国各地の食卓を彩っています。陶磁器の見本市や名工たちの工房が、この街の伝統を生き生きと守り続けています。'),
  'tangshan/lake': ('南湖公園', '南湖（なんこ）は、かつての炭鉱の地盤沈下地帯を湖と緑豊かな公園に生まれ変わらせたもので、今では街の緑の肺となっています。湖畔にはサイクリングロードと花の庭園が続き、この公園は大規模な園芸博覧会の会場にもなりました。工業都市が自然と和解した象徴なのです。'),
  'anshan/steel': ('鋼鉄の都', '鞍山（あんざん）は中国最大級の製鉄コンビナートが築かれた地で、「鋼都（こうと）」と呼ばれています。幾世代にもわたり、溶鉱炉の炎がこの街の夜を照らしてきました。ここでは鉄鋼づくりは単なる仕事ではなく、街のアイデンティティそのものなのです。'),
  'anshan/jade': ('岫岩玉', '鞍山地域の岫岩（しゅうがん）は、中国有数の翡翠（ひすい）の里です。市内の玉仏苑には、一枚岩の巨大な翡翠から彫り出された世界的に有名な仏像が安置されています。翡翠の工房や市場は、石に命を吹き込む匠の技であふれています。'),
  'anshan/mountain': ('千山', '「千の蓮の峰」を意味する千山（せんざん）は東北地方の霊山で、花崗岩の峰々が蓮の花びらのように連なっています。山腹には仏教と道教の寺院が点在し、坐した仏の姿に似ていることで名高い巨岩もあります。春になると、山は花の香りに包まれます。'),
  'anshan/spring': ('湯崗子温泉', '湯崗子（とうこうし）温泉では、千年ものあいだ人々が癒やしを求めてきました。関節の痛みに効くと信じられる鉱泉と温泉泥の湯あみは、幾世代にもわたって親しまれています。歴史を通じて君主や名士たちを迎えてきたこの温泉は、今も安らぎを求める人々の憩いの場です。'),
  'linyi/market': ('卸売市場', '臨沂（りんぎ）は中国北方最大の卸売取引の中心地で、巨大な市場ホールには針から家具まであらゆる商品がそろっています。ここから出発するトラックが、商品を国の隅々まで運んでいきます。このにぎわいが、街に「物流の都」の称号をもたらしました。'),
  'linyi/brush': ('書聖の故郷', '中国の「書聖」王羲之（おうぎし）は臨沂に生まれ、その流れるような筆致は千年以上にわたって手本とされてきました。街の記念祠や書道祭が、この遺産を今に伝えています。臨沂では、墨の香りが商いのざわめきに優雅な彩りを添えているのです。'),
  'linyi/mountain': ('蒙山', '沂蒙（ぎもう）山系の真珠と呼ばれる蒙山（もうざん）は、山東省で最も高い山のひとつです。深い森と滝、澄み切った空気は「天然の酸素バー」の名を山にもたらしました。ハイキングコース、山腹の村々、山の蜂蜜が、旅人に静かな逃避行を約束してくれます。'),
  'linyi/pancake': ('沂蒙煎餅', '紙のように薄く延ばしたトウモロコシと穀物の煎餅（ジエンビン）は、沂蒙山地の人々の昔ながらの主食です。熱した石の焼き板で焼き上げ、伝統的には新鮮な葱を巻いていただきます。日持ちがよく腹持ちのするこのパンは、山村の厳しい暮らしの忠実な友であり続けてきました。'),
  'cangzhou/lion': ('鉄獅子', '千年以上も立ち続ける巨大な鋳鉄の獅子は、滄州（そうしゅう）の誇り高き象徴であり、中国最大級の古代鉄器のひとつです。人々はこれを「鎮海吼（ちんかいこう）」、すなわち海を鎮める咆哮と呼び、洪水を抑えるために鋳造されたと伝えられています。街はこのシンボルを守り神のように大切にしています。'),
  'cangzhou/martial': ('武術の郷', '滄州は中国の「武術のふるさと」として知られ、八極拳（はっきょくけん）のような剛健で実戦的な流派がここで育ちました。かつて隊商を守った腕利きの用心棒の多くは、この街の出身だったのです。今日でも武術学校や大会が、その伝統を堂々と守り続けています。'),
  'cangzhou/canal': ('京杭大運河', '北京と杭州を結ぶ大運河は滄州の街の真ん中を貫き、街は何世紀にもわたり運河の交易で栄えました。古い船着き場や河岸の街並みには、当時の面影が今も残っています。運河沿いの公園は、今では夕方の散歩に人気のスポットです。'),
  'cangzhou/jujube': ('金糸ナツメ', '皮が薄く蜂蜜のように甘い滄州の「金糸小棗（きんしなつめ）」は、干し果物の王様とたたえられています。その名は、実を二つに割ったときに果肉から伸びる金色の甘い糸に由来します。秋の収穫期には果樹園が赤く染まり、ナツメ茶やナツメのお菓子は地元の食卓に欠かせません。'),
  'nantong/textile': ('南通紡績業', '南通（なんつう）の近代紡績の物語は、実業家・張謇（ちょうけん）が設立した紡績工場から始まりました。今日この街は中国のホームテキスタイルの都であり、寝具からカーテンまでの製品が世界の市場に届けられています。織物の文化は、地元の藍染めの型染め布の芸術にも息づいています。'),
  'nantong/mountain': ('狼山', '長江が海に注ぐ場所にそびえる五つの峰の狼山（ろうざん）は、この地方の霊山です。頂上に建つ何百年もの歴史を持つ仏教寺院へと続く石段を、巡礼者や旅人たちが登っていきます。山頂からは、大河と海との出会いが眼下に広がります。'),
  'nantong/kite': ('板鷂（バンヤオ）', '南通の「板鷂（ばんよう）」凧は、骨組みに取り付けられた数十個の小さな笛によって空でうなりを上げ、風が強まるとその音はオーケストラのように高鳴ります。この笛付き凧づくりは、世代から世代へ受け継がれてきた何百年もの歴史を持つ工芸で、地元の名匠たちが丹精込めて守り続けています。'),
  'nantong/school': ('近代教育発祥の地', '実業家であり改革者でもあった張謇は、その財産を故郷に捧げました。南通に近代的な学校や図書館、そして中国人自身の手で創られた中国初の博物館を開いたのです。おかげでこの街は教育の先駆者となりました。彼の「実業による救国」の理想は、今も街の記憶の中に生きています。'),
  'taizhou/opera': ('梅蘭芳', '京劇の伝説的名優・梅蘭芳（メイ・ランファン）のルーツは泰州（たいしゅう）にあります。彼が女形の役に吹き込んだ気品は、この芸術を世界に知らしめました。街の記念公園と博物館は、衣装や舞台写真を通してその遺産を伝えています。京劇の調べは、今も街の公園で聞くことができます。'),
  'taizhou/tea': ('早茶', '泰州の一日は「早茶（ザオチャ）」で始まります。濃く淹れたお茶とともに、蒸し饅頭、細く刻んだ干し豆腐の和え物、魚のつみれスープが食卓に並びます。ここでの朝のお茶は決して急ぎません。ご近所同士が茶館に集い、おしゃべりとともに一日が始まるのです。'),
  'taizhou/boat': ('溱潼ボートフェスティバル', '毎年春になると、渓潼（チントン）鎮の湿地に何百艘もの舟が集まります。漕ぎ手たちは太鼓の響きの中で競い合い、竿が水面を打つたびに白いしぶきが上がります。何百年も続くこの舟の祭りは、水郷文化の最も熱気あふれる一日であり、国の無形文化遺産に登録されています。'),
  'taizhou/meatball': ('獅子頭', '大きくて柔らかな豚肉の肉団子「獅子頭（シーズートウ）」は、淮揚（わいよう）料理の古典です。ふんわりとした食感が獅子のたてがみを思わせることからこの名が付きました。とろ火で何時間も煮込まれ、口の中でほろりと崩れます。カニの卵を加えた贅沢版は、秋の食卓で最も格式高いごちそうです。'),
  'jinhua/ham': ('金華ハム', '金華（きんか）ハムは、何世紀も続く塩漬けと風干しの製法でじっくり熟成されます。切り口の深い紅色と豊かな香りを持つ、中国で最も有名なハムです。多くはスープや煮込み料理に深い旨味を加えるために使われます。上質な金華ハムは、何年もの忍耐が実らせた逸品なのです。'),
  'jinhua/film': ('横店影視城', '金華地域にある横店（ヘンディエン）は、世界最大の野外映画スタジオで、紫禁城や古代王朝の宮殿の巨大なレプリカがそびえています。数え切れないほどの時代劇映画やドラマがここで撮影されています。セットを見学していると、衣装をまとった俳優たちとすれ違うこともあるでしょう。'),
  'jinhua/cave': ('双龍洞', '双龍洞（そうりゅうどう）、すなわち「二匹の龍」の洞窟への入り方は忘れがたい体験です。訪れる人は低い岩の門の下を、小舟に仰向けに横たわってすべるように入ります。中には鍾乳石と石筍に飾られた涼しい地底世界が広がっています。この洞窟は、昔の旅人たちの紀行文でも賞賛されました。'),
  'jinhua/bridge': ('江南の古橋', 'かつて婺州（ぶしゅう）と呼ばれた金華の周辺には、アーチ形の石橋と水路の巡る水郷が点在しています。白壁に黒瓦の家々が水面に映り、橋のたもとには茶館が軒を連ねます。この風景は、江南地方の優雅な暮らしぶりを現代に伝えています。'),
  'wuhu/park': ('方特遊楽園', '蕪湖（ぶこ）には、中国最大級のテーマパーク群があり、ジェットコースターからアニメーションの世界まで、家族連れにスリル満点の一日を提供しています。おかげでこの街は地域のエンターテインメントの都へと成長し、週末には近隣の省から大勢の観光客が押し寄せます。'),
  'wuhu/ironart': ('鉄画', '蕪湖の「鉄画（てつが）」芸術では、鍛えた鉄が筆致を思わせる優雅な絵へと姿を変えます。約三百年の歴史を持つこの工芸は、水墨画の精神を金属に映し取ったものです。名匠たちは金槌と金床で山や松、鳥の姿を描き出します。これらの作品は、この街ならではの最高の贈り物です。'),
  'wuhu/rice': ('米の港', '蕪湖は歴史を通じて中国最大級の米市場のひとつでした。長江に面した立地のおかげで、南方の収穫はここで取り引きされたのです。埠頭で米袋を担いだ人夫たちの姿は今では近代的な倉庫に取って代わられましたが、街は穀物交易の遺産を今も誇りにしています。'),
  'wuhu/river': ('長江港', '長江沿いの活気ある港は、蕪湖を安徽省が世界へ開く玄関口にしています。川沿いでは貨物船とコンテナクレーンが休むことなく動き続け、水辺の公園からそのにぎわいを眺めるのも一興です。この川は街に交易と、夕べの涼やかな風の両方を運んでくれるのです。'),
  'huangshan/peak': ('黄山', '花崗岩の峰々、雲海、曲がりくねった松、そして温泉を持つ黄山（こうざん）は、中国で最も有名な山であり、ユネスコ世界遺産です。「四絶」と呼ばれるこれらの美しさは、何世紀にもわたって画家や詩人にインスピレーションを与えてきました。日の出のとき雲の上に立つ体験は、一生の思い出になります。'),
  'huangshan/village': ('宏村', '白壁と黒瓦の徽州（きしゅう）様式の村・宏村（こうそん）は、水路と月の形をした池を持ち、まるで絵から抜け出したような姿で、ユネスコ世界遺産に登録されています。村の設計は牛の体をかたどっているといわれます。朝もやが湖に降りると、画家たちが岸辺にイーゼルを立てるのです。'),
  'huangshan/tea': ('黄山毛峰', '霧深い山の斜面で摘まれる黄山毛峰（こうざんもうほう）は、中国で最も有名な緑茶のひとつで、うぶ毛をまとった峰の形の茶葉からその名が付きました。早春の一番摘みが最も珍重されます。茶碗にほのかな蘭の香りを残すその味わいは、山の雲がそのまま茶葉に織り込まれたかのようです。'),
  'huangshan/ink': ('徽墨', 'かつての徽州地方は、中国で最も格式高い墨と硯（すずり）を生み出し、書家たちは何世紀もこの地の品を求めてきました。木彫り、煉瓦彫り、石彫りで飾られた邸宅もまた、同じ職人の心から生まれたものです。徽州文化は、墨と建築をひとつの美意識に結びつけているのです。'),
  'yichun/moon': ('明月山', '「明るい月」を意味する明月山（めいげつざん）は宜春（ぎしゅん）のシンボルで、この街は月をテーマにした祭りでも知られています。ロープウェイは崖沿いの遊歩道や高原の草地へと訪れる人を運びます。山頂で霧が晴れると、眼下の谷々が銀色の光に輝きます。'),
  'yichun/spring': ('温泉', '宜春の温湯（うぇんたん）鎮に湧く温泉は、希少なセレンを豊富に含み、古くから癒やしの力があるとされてきました。温泉ホテルと露天風呂は一年を通して訪れる人を迎えます。山の空気と湯けむりの出会いが、この街を中国屈指の温泉保養地にしたのです。'),
  'yichun/zen': ('禅宗', '宜春の山々は、中国の禅仏教の重要な宗派が生まれた土地のひとつで、何百年もの歴史を持つ寺院が静かな谷あいに点在しています。僧たちの茶畑と坐禅堂は、訪れる人をゆったりとした時間へと誘います。鐘の音が、霧に包まれた森にこだまします。'),
  'yichun/rice': ('袁河平原', '袁河（えんが）の肥沃な平野は、古くから江西省の穀倉地帯でした。水に恵まれた田んぼは、毎年豊かな米の実りをもたらします。村々では収穫の季節がお祭りのように過ぎていきます。新米で作る地元の米麺と米の酒が、平野の恵みを食卓に届けてくれるのです。'),
  'zhangzhou/narcissus': ('水仙', '中国で最も有名な水仙の球根は漳州（しょうしゅう）で育てられ、この花は春節に欠かせない飾りです。職人たちは球根に特別な切り込みを入れ、花が優美な形に開くように仕立てます。新年に家で咲く一鉢の水仙は、来る年の幸運のしるしとされています。'),
  'zhangzhou/tulou': ('客家土楼', '土を突き固めて築かれた巨大な円形の要塞住居「土楼（どろう）」は、村ひとつをまるごと一つの屋根の下に集めた住まいで、ユネスコ世界遺産に登録されています。分厚い壁は防御と涼しさの両方をもたらし、中庭では共同の暮らしが何世紀も続いてきました。緑の丘の間に連なる土楼の群れは、おとぎ話のような風景を描き出します。'),
  'zhangzhou/banana': ('トロピカルフルーツ', '温暖で湿潤な漳州のデルタ地帯は、一年中果物を実らせます。バナナ園、リュウガンの林、ミカン畑が地平線まで続きます。この地方の大きくて瑞々しいザボンも食卓の人気者です。果物市場は季節を問わず、色と香りの祭典です。'),
  'zhangzhou/coast': ('東山島', '黄金色の砂浜と漁村を持つ東山島（とうざんとう）は、南の海岸の真珠です。島いちばんの名物は、崖っぷちで絶妙なバランスを保ち、風にそよそよと揺れると言い伝えられる巨大な「風動石」です。夕方になると、港に帰る船が獲れたての魚を運んできます。'),
  'guangzhou/tower': ('広州塔', '珠江のほとりにそびえるこの塔は、ほっそりとねじれたシルエットから「小蛮腰（スモール・ウエスト）」の愛称で親しまれています。世界有数の高さを誇り、夜になると無数のLEDが色を変えながら輝き、広州の近代的なスカイラインを飾る王冠のような存在です。'),
  'guangzhou/dimsum': ('飲茶', '広州の朝は「飲茶（ヤムチャ）」で始まります。香り高いお茶とともに、竹せいろで蒸した点心が次々とテーブルに並びます。エビ蒸し餃子やシュウマイ、サクサクのパイをつまみながら何時間もおしゃべりを楽しむこの習慣は、広東の食文化の心そのものです。'),
  'guangzhou/academy': ('陳氏書院', '清代末期に陳姓の一族が資金を出し合って建てたこの壮麗な祖先廟は、木彫りや石の浮き彫り、屋根を埋め尽くす色鮮やかな陶製の人形で有名です。現在は民俗芸術の博物館として、中国南方の工芸の最高峰を紹介しています。'),
  'guangzhou/flower': ('花の都', '温暖な気候のおかげで広州では一年中花が咲き、古くから「花城（花の都）」と呼ばれてきました。旧正月の前には街いっぱいに大きな花市が開かれ、新年の幸運を願って家族連れが金柑の木や桃の花を買い求めます。'),
  'wuhan/crane': ('黄鶴楼', '長江を見下ろす黄鶴楼は、三国時代にまでさかのぼる歴史を持つ、中国で最も名高い楼閣のひとつです。崔顥や李白といった詩人たちの名句に詠まれ、幾度も焼失と再建を繰り返しながらも、その詩情あふれる魂は今も生き続けています。'),
  'wuhan/noodle': ('熱乾麺', '熱乾麺（レーガンミエン）は、ゆでたコシのある麺を濃厚なごまだれと漬物、ねぎで和えた料理です。武漢の人々は屋台で一杯買って一日を始めます。朝食がとても大切にされるこの街では、朝ごはんの時間を「過早（グオザオ）」という特別な言葉で呼ぶほどです。'),
  'wuhan/duckneck': ('鴨の首のスパイス煮', '唐辛子や香辛料の効いたスープで何時間も煮込んだ鴨の首は、武漢で一番愛されているおやつです。骨からしゃぶるように食べるしびれる辛さのこの味は、夏の夜、川辺でのおしゃべりや冷たいビールに欠かせないお供です。'),
  'wuhan/university': ('武漢大学の桜', '毎年春になると、武漢大学の歴史あるキャンパスは薄紅色と白の桜の雲に包まれ、中国全土から見物客が訪れます。珞珈山のふもとに建つ古い校舎と花々が織りなす光景は、この街で最もロマンチックな春の風物詩です。'),
  'tianjin/eye': ('天津の目', '海河に架かる橋の真ん中にそびえる「天津之眼」は、流れる水の真上に建つ世界でも珍しい観覧車です。頂上に着くと川の両岸が一度に眼下に広がり、片側にはヨーロッパ風の街並み、もう片側にはガラスの高層ビル群が輝きます。'),
  'tianjin/baozi': ('狗不理包子', '清の時代から作られている狗不理（ゴウブリー）の蒸し饅頭は、薄い皮とジューシーな豚肉あん、美しく折り込まれたひだで知られる天津名物です。「犬も見向きもしない」という不思議な名前は、創業者が饅頭作りに夢中でお客と話す暇もなかったという言い伝えに由来します。'),
  'tianjin/crosstalk': ('相声', '相声（シアンション）は、二人の芸人がテンポのよい掛け合いや言葉遊び、ものまねで観客を笑わせる伝統的な話芸です。天津の茶館で育まれたこの芸能は、街に「中国コメディーのゆりかご」という名声をもたらし、今も湯気の立つお茶を楽しみながら鑑賞されています。'),
  'tianjin/architecture': ('五大道', '五大道（ウーダーダオ）と呼ばれる地区には、外国租界時代に建てられた数百棟のヨーロッパ風の洋館が残っています。イギリス、フランス、イタリアの様式が軒を連ねるこの街並みは、天津に「世界建築の博物館」という愛称を与えました。馬車や自転車での散策がおすすめです。'),
  'xiamen/island': ('コロンス島', '厦門（アモイ）の沖に浮かぶコロンス島では自動車の乗り入れが禁止されており、細い路地には足音とピアノの調べだけが響きます。かつての領事館やブーゲンビリアに包まれた洋館が並ぶこの島は、ユネスコ世界遺産に登録された、フェリーですぐの野外博物館です。'),
  'xiamen/piano': ('ピアノの島', '19世紀、宣教師や商人たちとともに西洋音楽がコロンス島に根づきました。一世帯あたりのピアノの数が非常に多いことから「ピアノの島」と呼ばれるこの島には、ピアノ博物館があり、何世代にもわたる音楽の伝統が今も受け継がれています。'),
  'xiamen/egret': ('シラサギ', '厦門の古い名前「鷺島（ルーダオ）」は「サギの島」という意味で、優雅な白いサギは今も海辺や湿地の上を舞っています。街のシンボルとなったこの鳥は、彫刻から通りの名前まで至るところに登場し、厦門と海や自然との深い結びつきを物語っています。'),
  'xiamen/oyster': ('牡蠣オムレツ', '新鮮なカキを卵とサツマイモのでんぷんでとじ、外はカリッと中はふんわり焼き上げるこのオムレツは、閩南（ミンナン）地方を代表する屋台の名物です。厦門の夜市では甘辛いソースを添えて出され、海峡の向こうの台湾でも同じように愛されています。'),
  'harbin/ice': ('ハルビン氷祭り', '毎年冬、凍った松花江から切り出した巨大な氷のブロックで宮殿や塔、すべり台が造られ、夜には色とりどりの光に照らされて街はおとぎの国に変わります。ハルビン氷雪祭りは世界最大の氷の祭典として、何百万人もの観光客を迎えています。'),
  'harbin/cathedral': ('聖ソフィア大聖堂', '緑のタマネギ型ドームと赤レンガの壁を持つ聖ソフィア大聖堂は、ハルビンのロシア鉄道時代を伝える最も壮麗な建物です。現在は建築博物館として使われ、その前の広場ではハトが舞い、ストリートミュージシャンが演奏する、市民に愛される待ち合わせの場所となっています。'),
  'harbin/sausage': ('ハルビン紅腸', '一世紀以上前、ロシア移民のレシピをもとに作られ始めた燻製の赤いソーセージは、ハルビンを象徴する味です。薪の煙の香りとほのかなニンニクの風味は、焼きたてのパンや冷たいビールと相性抜群で、この街のヨーロッパ的なルーツを食卓に届けてくれます。'),
  'harbin/accordion': ('音楽の都', 'ロシアからの移住者がもたらしたバイオリンやアコーディオン、オペラの文化により、ハルビンは早くから中国における西洋音楽の中心地のひとつになりました。中国初期の交響楽団の本拠地でもあるこの街は、毎年夏に開かれる歴史ある音楽祭で「音楽の都」の名を守り続けています。'),
  'fuzhou/alley': ('三坊七巷', '「三坊七巷（さんぼうしちこう）」は、白壁と黒瓦の家々が残る明・清時代の街並みです。狭い石畳の路地にはかつて学者や政治家が暮らしていました。今では中庭のある屋敷に茶館や工芸品店が入り、古い街区が生きた博物館として息づいています。'),
  'fuzhou/banyan': ('榕城', '宋の時代に始まった植樹のおかげで、福州の街路は樹齢数百年のガジュマルで埋め尽くされました。長いひげのように垂れ下がる気根を持つこの大木は、蒸し暑い夏に涼しい木陰を作ってくれます。そのため福州は「榕城（ようじょう）」、つまりガジュマルの街と呼ばれています。'),
  'fuzhou/hotspring': ('福州温泉', '福州では市の中心部から天然の温泉が湧き出しており、千年以上にわたって入浴文化を育んできました。人々は今も街角の温泉で疲れを癒やしています。地熱の宝の真上に築かれた福州は、中国でも珍しい温泉の都のひとつです。'),
  'fuzhou/soup': ('仏跳牆', '仏跳牆（ぶっちょうしょう）は、ホタテやキノコ、アワビなど数十種類もの高級食材を土鍋で何時間も煮込んだ伝説的なスープです。その名は「あまりの香りに修行僧でさえ壁を跳び越えて味見に来る」と詠んだ詩に由来し、福建料理の最高峰とされています。'),
  'dongguan/robot': ('世界の工場', '珠江デルタの中心に位置する東莞（トンコワン）は、世界の電子製品やおもちゃのかなりの部分を生産してきた巨大な工業都市です。労働集約型の組み立てラインは次第にスマート工場とロボットアームに置き換わりつつあり、「世界の工場」は新しい時代へと生まれ変わろうとしています。'),
  'dongguan/basketball': ('バスケットボールの街', '東莞ではバスケットボールが大変な人気で、ほぼすべての地区にコートがあり、街角からプロリーグへと続く育成の道が整っています。中国リーグで最多級の優勝を誇る広東サザンタイガースの本拠地でもあり、東莞は公式に中国の「バスケットボールの街」に認定されています。'),
  'dongguan/keyuan': ('可園', '清代の役人が築いた可園（かえん）は、限られた敷地に楼閣や池、曲がりくねった回廊を見事に収めたことで知られています。広東の四大名園のひとつに数えられ、中国南方の造園芸術の繊細な美をぎゅっと凝縮して見せてくれます。'),
  'dongguan/cannon': ('虎門砲台', '虎門（フーメン）の砲台は、かつてずらりと並んだ大砲で珠江の河口を守っていた要塞です。1839年、欽差大臣の林則徐がこの岸辺で没収したアヘンを処分したことがアヘン戦争の引き金となりました。今日、砲台と博物館が中国近代史の転換点を伝えています。'),
  'lanzhou/beefnoodle': ('蘭州牛肉麺', '蘭州の手延べ麺は有名な決まりごとで語られます。澄んだ牛骨スープ、白い大根、赤いラー油、そして緑の香菜です。職人が目の前で数秒のうちに生地を細い麺へと引き伸ばす一杯は、この街の朝の習慣であり、中国で最も有名な麺料理のひとつです。'),
  'lanzhou/waterwheel': ('水車', '明の時代、黄河の水を畑にくみ上げるために造られた巨大な木製の水車は、蘭州の変わらぬシンボルとなりました。川沿いの水車公園では忠実に復元された水車が今も回り続け、そのゆっくりときしむ音が、何世紀にもわたる灌漑の知恵を伝えています。'),
  'lanzhou/statue': ('黄河母親像', '川岸に立つ「黄河母親像」は、流れるような髪の穏やかな母親が胸に幼子を抱く姿を表しています。母は中華文明を育んだ黄河を、子どもはその流れから生まれた人々を象徴しており、蘭州が黄河に寄せる深い思いを最も力強く伝える像です。'),
  'lanzhou/raft': ('羊皮筏子', '空気を入れた羊の皮を木の枠にくくり付けて作るいかだは、何世紀にもわたり黄河で荷物や人を運んできました。今日ではこの伝統的な羊皮いかだが蘭州の川辺で観光客を乗せて進み、濁流の上をゆったりと漂う体験は、この街で最も本物らしい思い出になります。'),
  'urumqi/bazaar': ('国際大バザール', 'ウルムチの国際大バザールは、イスラム建築に着想を得た塔とドーム型の市場ホールで、シルクロード交易の精神を今に伝えています。露店にはドライフルーツや香辛料、絹、手作りのナイフがあふれ、夜になると広場は音楽と踊りのショーでにぎわいます。'),
  'urumqi/tianshan': ('天池', '天山山脈の雪をいただくボゴダ峰のふもとに広がる天池（てんち）、すなわち「天の湖」は、深い青色の水で知られています。トウヒの森に囲まれたこの湖は、伝説では西王母が宴を開いた場所とされ、ユネスコ世界遺産の天山山脈の一部となっています。'),
  'urumqi/kebab': ('羊肉串', '炭火の上でジュージューと焼ける羊肉の串には、クミンと唐辛子がたっぷりまぶされ、その煙の香りがウルムチの街中に漂います。ウイグル料理を象徴するケバブは、タンドール窯から出したての焼きたてナンと濃いお茶とともに、夜市で味わうのが一番です。'),
  'urumqi/dance': ('ウイグル舞踊', '太鼓やラワープ、ドタールの弦の音に合わせてくるくると舞うウイグルの踊りは、結婚式やお祭りの花形です。優雅な手の動きと次第に速くなる回転が特徴のこの踊りは、喜びを分かち合う共同体の芸術であり、お客さんも必ず輪の中に招かれて一緒に踊ります。'),
  'haikou/coconut': ('ココナッツの街', '海南島の省都・海口（ハイコウ）では、大通りがココヤシの並木に覆われているため、「椰城（やじょう）」、つまりココナッツの街と呼ばれています。屋台の売り子がなたを一振りして開けてくれる冷たいココナッツジュースは、南国の暑さをいやす一番自然な特効薬です。'),
  'haikou/arcade': ('騎楼老街', '海口の古い商店街には、東南アジアから帰ってきた華僑の商人たちが建てた「騎楼（きろう）」というアーケード式の店舗建築が並んでいます。一階部分が日陰の回廊になっており、南国の強い日差しや雨から買い物客を守るこの優美な建築は、およそ一世紀にわたり街の暮らしを支えてきました。'),
  'haikou/crater': ('火山群', '海口の郊外に広がる古い火山地帯は、死火山の噴火口と溶岩トンネルが残る緑豊かなジオパークになりました。太古の噴火が残した玄武岩は今も村の家や畑の石垣に使われており、訪れる人は噴火口の底まで歩いて下りることができます。'),
  'haikou/turtle': ('熱帯の海', '海南島沿岸の暖かく澄んだ海は、サンゴ礁や海草の草原など豊かな生命を育んでいます。ウミガメはこの海岸で餌をとり、産卵します。保護活動のおかげで、子ガメたちが波に向かって駆け出す姿が、再び希望に満ちた光景として見られるようになりました。'),
  'luoyang/grotto': ('龍門石窟', '伊河をはさむ両岸の崖に彫られた龍門石窟は、数万体もの仏像を擁するユネスコ世界遺産です。北魏の時代に始まり唐代に最盛期を迎えた造像の中でも、穏やかなほほえみをたたえた巨大な盧舎那仏（るしゃなぶつ）が最高傑作とされています。'),
  'luoyang/peony': ('牡丹の都', '洛陽は唐の時代から牡丹の街として知られてきました。伝説によれば、女帝・武則天の「冬に咲け」という命令に唯一従わなかった花が、この地に追放されたのだといいます。毎年4月の牡丹祭りには街全体が色彩に包まれ、「花の王」と呼ばれるこの花をたたえます。'),
  'luoyang/whitehorse': ('白馬寺', '西暦68年に創建された白馬寺は、中国最初の仏教寺院とされています。その名は、インドから経典を背に運んだと伝えられる白い馬にちなんでいます。仏教が中国に伝来した象徴であるこの寺は、今も参拝や巡礼でにぎわう現役の祈りの場です。'),
  'luoyang/capital': ('古都', '洛陽は漢や唐を含む十三の王朝の都として、中国史の中心に位置してきました。黄河流域に栄えたこの古都はシルクロードの東の起点のひとつでもあり、博物館や遺跡が数千年におよぶ王朝の記憶を守り伝えています。'),
  'shantou/gongfutea': ('工夫茶', '潮汕（ちょうさん）地方の工夫茶（クンフーチャ）は、小さな茶杯に何度も注いでは飲み干す、儀式のようなお茶の芸術です。この土地でお客にお茶を差し出すことは最も深い敬意の表れであり、三つの茶杯の並べ方や繊細な手の動きは、代々大切に受け継がれています。'),
  'shantou/beefpot': ('牛肉火鍋', '潮汕の牛肉しゃぶしゃぶ鍋は、鮮度への徹底したこだわりで知られています。その日にさばいた牛肉を部位ごとに分け、澄んだスープの中でわずか数秒単位でしゃぶしゃぶします。切り身ごとに決まったゆで時間があり、ピーナッツ風味のサテソースにつけると、肉本来の甘みが引き立ちます。'),
  'shantou/opera': ('潮劇', '数百年の歴史を持つ潮劇（ちょうげき）は、潮州方言で歌われる繊細な旋律と、きらびやかな刺繍の衣装で観客を魅了します。海を渡った潮汕出身の移民たちによって東南アジアにも広まったこの舞台芸術は、今も人々と故郷を結ぶ絆であり続けています。'),
  'shantou/harbor': ('汕頭港', '19世紀に外国貿易へ開かれた汕頭（スワトウ）の港は、数えきれないほどの潮汕の人々が海外へ渡っていった玄関口となりました。東南アジアの多くの華人家庭のルーツはこの地にあり、移民たちが故郷に送った「僑批（きょうひ）」と呼ばれる手紙が、その絆の証として大切にされています。'),
  'baoding/mansion': ('直隷総督署', '直隷総督署は、清の時代に都を取り囲む直隷省を治めた総督たちの役所でした。李鴻章や袁世凱といった実力者たちがここで政務を執りました。保存状態のよい中庭や広間は、王朝時代の地方統治を生き生きと伝える貴重な記録です。'),
  'baoding/donkeyburger': ('ロバ肉バーガー', '「驢肉火焼（ロバ肉のサンド）」は、じっくり煮込んだ香辛料の効いたロバ肉を、窯から出したてのパリパリのパンに挟んだ料理です。「天には竜の肉、地にはロバの肉」という地元のことわざでたたえられるこの味は、保定で一番有名な屋台料理であり、街の誇りです。'),
  'baoding/balls': ('健康球', '手のひらの上で回して使う金属製の保定健身球は、明の時代から作られてきた伝統的な手の運動具です。中に仕込まれた音板が回転とともに高い音と低い音を奏でます。日々の練習は指の柔軟さを養い、心を落ち着かせるとも信じられています。'),
  'baoding/reeds': ('白洋淀', '華北最大級の湿地帯である白洋淀（はくようでん）は、アシに縁どられた水路で結ばれた数百の池からなる迷路のような水郷です。夏にはハスの花が水面を覆い、アシ原は鳥のさえずりに包まれます。村人たちは今も細い小舟で魚をとり、アシを刈っています。「北国の真珠」と呼ばれるゆえんです。'),
  'jilin/rime': ('霧氷', '冬の夜、凍らない松花江から立ちのぼる水蒸気が川辺の木々の枝に凍りつき、水晶のような真っ白い霧氷になります。「霧凇（ウーソン）」と呼ばれるこの現象は中国四大自然奇観のひとつに数えられ、朝日を浴びて銀色に輝く木々は、おとぎ話のような光景を見せてくれます。'),
  'jilin/snowboard': ('スキーリゾート', '長く雪深い冬を持つ吉林は、中国有数のウィンタースポーツの本場です。周囲の山々に整備された近代的なリゾートは、さらさらのパウダースノーでスキーヤーやスノーボーダーを引き寄せ、この地域は国の冬季競技選手を数多く育ててきました。'),
  'jilin/meteorite': ('吉林隕石博物館', '1976年、吉林の上空で隕石が砕け散り、記録に残る中でも最大級の石質隕石雨が降り注ぎました。1トンを超える最大の本体は市内の隕石博物館に展示されており、訪れる人は宇宙からやって来たこの客人と間近に対面することができます。'),
  'jilin/skate': ('凍結した松花江', '冬が訪れると、松花江の流れの穏やかな区間は厚い氷に覆われ、市民の天然スケートリンクに変わります。スケーターが滑り、お年寄りは氷上でこまを回し、子どもたちはそりで競走します。寒い季節、川辺は吉林で一番にぎやかな集いの場になるのです。'),
  'ordos/khan': ('チンギス・ハーン廟', 'オルドス草原に立つチンギス・ハン陵は、モンゴルのゲルをかたどった三つの大きなドームの下に偉大なハンをまつる霊廟です。ダルハドと呼ばれる守り人たちが何世紀にもわたって儀式の火と供物を絶やさず守り続けており、この廟はモンゴル文化で最も神聖な場所のひとつとされています。'),
  'ordos/cashmere': ('カシミヤ', 'オルドス草原の厳しい冬に耐えるヤギの細い産毛からは、世界最高級のカシミヤが生まれます。「柔らかな黄金」と呼ばれるこの繊維はオルドスを世界的なカシミヤ生産の中心地に押し上げ、遊牧の伝統を現代の高級産業へと変えました。'),
  'ordos/sanddune': ('響沙湾', 'クブチ砂漠の巨大な砂丘は、斜面を滑り降りると深く響く低いうなりを上げるため、「鳴き砂」と呼ばれています。ラクダのキャラバンで砂丘を越えたり、サンドボードで滑ったりできるほか、夕日が砂を黄金色に染めるころ、砂漠は静かな詩のような世界になります。'),
  'ordos/yurt': ('パオ', '白いフェルトで覆われた丸いモンゴルのゲルは、草原の風に耐えながらも、次の移動のときには簡単にたたんで運べるように作られています。入り口は南を向き、中央のかまどが家族の暮らしの中心です。オルドス草原のゲルに泊まることは、遊牧民のもてなしを味わう最高の方法です。'),
  'jining/confucius': ('孔廟', '済寧市に属する曲阜（きょくふ）は、偉大な思想家・孔子の生まれた街です。孔子をまつる孔廟、子孫が暮らした孔府、一族の墓地である孔林は、あわせてユネスコ世界遺産に登録されています。糸杉の茂る中庭と古い石碑は、二千年以上にわたる敬愛の静かな証人です。'),
  'jining/barge': ('京杭大運河', '北京と杭州を結ぶ京杭大運河の要港であった済寧は、何世紀にもわたり穀物を運ぶはしけ船と商人たちでにぎわいました。運河の交易は街に富と活気ある波止場文化をもたらし、この大水路の南部区間では今も貨物が運ばれています。'),
  'jining/sword': ('梁山泊の好漢', '古典小説『水滸伝』では、無実の罪に苦しめられた108人の豪傑たちが、沼沢に囲まれた梁山（りょうざん）の山塞に集います。宋江に率いられたこの好漢たちは、権力者に立ち向かい貧しい人々のために戦いました。今日の梁山は、物語の名場面を再現した文化スポットとして訪問者を迎えています。'),
  'jining/fishnet': ('微山湖', '華北最大級の淡水湖である微山湖（びざんこ）は、夏になると地平線まで続くハスの花畑に覆われます。漁師の家族は代々受け継がれた方法で網を打ち、湖のリズムに寄り添って暮らしています。地元の食卓では、新鮮な魚とシャキシャキのレンコンが主役です。'),
  'langfang/culture': ('シルクロード文化センター', '北京と天津の間に位置する廊坊（ろうぼう）の巨大な現代文化センターは、シルクロードをテーマにした展示、舞台芸術、工芸をひとつ屋根の下に集めています。隊商路の美意識に着想を得たこの建物は、二つの大都市を結ぶ文化の懸け橋というこの街の役割を象徴しています。'),
  'langfang/furniture': ('家具城', '廊坊市の香河（こうが）県は、中国最大級の家具の生産・販売拠点です。何キロメートルも続くショールームや工房では、伝統的な紫檀の細工から現代デザインまであらゆるスタイルがそろい、華北一帯で新居を構える家族の多くがここへ買い物にやって来ます。'),
  'langfang/tunnel': ('古戦道', '宋王朝と北方の遼との国境地帯には、防衛のために秘密の地下トンネル網が掘られました。約千年の時を経てなお残るレンガ造りの通路には、通気孔や待ち伏せ用の部屋が備わっており、古の国境戦争を地下から静かに物語っています。'),
  'langfang/themepark': ('第一城', '「天下第一城」は、古い北京の城壁と城門を壮大に再現した巨大テーマパークです。縁日を模した廟会や伝統芸能のショー、古典様式の建築が楽しめるこの場所は、家族連れを都の輝かしい過去への旅へと連れ出してくれます。'),
  'yancheng/salt': ('塩城', '塩城（えんじょう）の名は「塩の街」を意味します。沿岸の塩田は何世紀にもわたり王朝の国庫を潤してきました。太陽の下で海水を蒸発させて得る塩がこの街の運命を形づくり、その遺産は今も博物館や地名、土地の言い伝えの中に生き続けています。'),
  'yancheng/crane': ('タンチョウ', '塩城の沿岸湿地は、野生のタンチョウにとって世界最大の越冬地です。中国文化で長寿と気品の象徴とされるこの美しい鳥は、毎年冬に北から渡ってきます。アシ原の上をゆったりと舞う姿は、バードウォッチャーたちを魅了してやみません。'),
  'yancheng/elk': ('シフゾウ', 'シフゾウ（ミールー鹿）は、かつて中国の野生では絶滅し、海外の公園でしか生き残っていませんでした。塩城の大豊（だいほう）保護区に再導入された鹿たちはここで繁殖し、今では世界最大のシフゾウの群れが、この湿った海辺の草原を自由に駆け回っています。保護活動の輝かしい成功例です。'),
  'yancheng/wetland': ('沿岸湿地', '黄海沿岸に広がる干潟は、渡り鳥の壮大な中継地としてユネスコ世界遺産に登録されています。東アジア・オーストラリア間の渡りルートを行き来する数百万羽のシギ・チドリ類がここで羽を休めて栄養を蓄え、春と秋には干潟が羽ばたきの音で満たされます。'),
  'huzhou/brush': ('湖筆', '湖州（こしゅう）で作られる湖筆（こひつ）は、書道具の「文房四宝」に数えられる筆の中でも最も格式の高いものです。ヤギやウサギ、イタチの毛を数十におよぶ緻密な工程で仕上げた穂先は、鋭さとしなやかさを兼ね備えており、書家にとって計り知れない宝物です。'),
  'huzhou/bamboo': ('安吉竹海', '安吉（あんきつ）県の丘を覆う竹林は、風に揺れる果てしない緑の海のようです。映画『グリーン・デスティニー』の忘れがたい名場面の舞台となったこの竹林は、ひんやりした空気と遊歩道、そしてやわらかいタケノコを使った郷土料理で、訪れる人を癒やしてくれます。'),
  'huzhou/silkworm': ('養蚕', '太湖の南岸に位置する湖州は、数千年にわたり桑蚕（そうさん）絹織物の中心地であり続けてきました。桑畑と養魚池を組み合わせた伝統的な生産システムは、今では世界農業遺産に認定されています。湖州の絹は、歴史を通じて皇帝や宮廷の人々を装ってきました。'),
  'huzhou/whitetea': ('安吉白茶', '安吉白茶は、名前に反して実は緑茶です。春に出る新芽がほとんど白く見えるほど淡い色をした、珍しい品種から作られます。渋みが少なく、甘くみずみずしい味わいで茶好きに愛されており、収穫期がごく短いことから、中国で最も入手困難なお茶のひとつとなっています。'),
  'quzhou/go': ('囲碁', '伝説によると、爛柯山（らんかざん）で木こりが二人の仙人の囲碁を見物するうちに時のたつのを忘れ、気づけば斧の柄が朽ち果てていたといいます。この物語のおかげで衢州（くしゅう）は囲碁の聖地とあがめられ、この古い戦略ゲームは街をあげて大切にされています。'),
  'quzhou/peaks': ('江郎山', '江郎山（こうろうざん）の三本の巨大な石柱は、緑の森の中から空に向かってまっすぐそそり立っています。「丹霞（たんか）」と呼ばれる赤い砂岩地形の傑出した例としてユネスコ世界遺産に登録されており、石柱の間の狭い裂け目を歩くのは、めまいがするほどスリリングな体験です。'),
  'quzhou/ponkan': ('衢州ポンカン', '衢州の温暖な丘陵で育つポンカンは、むきやすい皮と蜂蜜のように甘い果肉で有名です。晩秋になると果樹園は一面のオレンジ色に染まり、収穫の季節には家族が木々の間に集います。この果実は、地域の冬の食卓を明るく彩ってくれます。'),
  'quzhou/cake': ('焼き餅', '衢州の窯焼き焼餅は、発酵させた生地を熱い窯の内壁に貼りつけて焼き上げます。ゴマをまぶしたパリパリの皮の中には、風味豊かな具が隠れています。朝、店の前にできる行列を見れば、地元の人々がこの一日の始まりをどれほど愛しているかがわかります。'),
  'huainan/tofu': ('豆腐発祥の地', '言い伝えによると、豆腐は漢の時代、淮南王・劉安に仕える八公山の錬丹術士たちが豆乳を固めたことから生まれたといいます。およそ二千年前にこの地で発明されたこの素朴な食べ物は世界中の食文化に広がり、淮南（わいなん）は毎年豆腐祭りを開いてその遺産を祝っています。'),
  'huainan/coalmine': ('炭鉱の街', '豊かな炭層の上に築かれた淮南は、長らく中国東部のエネルギー基地として働いてきました。炭鉱と発電所が地域の電力を支える一方で、市はかつての採掘地を湖や公園へと生まれ変わらせ、産業の遺産をより緑豊かな未来へと導いています。'),
  'huainan/oldtown': ('寿県古城', '寿県（じゅけん）の古城は、宋代の城壁が完全な形で残る中国でも数少ない街のひとつです。分厚いレンガの城壁とアーチ型の城門は、洪水からも街を守ってきました。城壁内の古い通りには、最後の都をこの地に置いた古代の楚（そ）の国の面影が残っています。'),
  'huainan/classic': ('淮南子', '『淮南子（えなんじ）』は、漢の時代に淮南王・劉安の宮廷に集められた学者たちが編纂した哲学の古典です。道家思想と宇宙論、統治術を織り交ぜたこの書物は、女神・女媧（じょか）が壊れた天を修復する物語など、愛される神話の数々も今日に伝えてくれました。'),
  'jingdezhen/porcelain': ('磁器の都', '景徳鎮（けいとくちん）は千年以上にわたって磁器を焼き続け、官窯の中心地として最高の作品を宮廷に納めてきました。磁器の原料であるカオリン（高嶺土）の名は、近郊の高嶺（ガオリン）村に由来します。この街は今日も、世界中から陶芸家たちを引き寄せています。'),
  'jingdezhen/kiln': ('古窯', '古窯民俗博覧区では、薪で焼く伝統的な窯と工芸の工房が今も生き続けています。山の斜面を這う龍窯から卵形の窯まで、磁器が炎の試練をくぐる様子を見学でき、職人たちがろくろを回し、釉薬をかけ、絵付けをする姿を目の前で見ることができます。'),
  'jingdezhen/bluewhite': ('青花磁器', '純白の磁器に釉薬の下からコバルトブルーの文様を描く「青花（せいか）」は、景徳鎮の世界的に名高い代名詞です。元と明の時代に完成されたこの染付の様式は、シルクロードと海の交易路を通じて世界に広まり、ヨーロッパの宮廷では熱狂的に収集されました。'),
  'jingdezhen/painting': ('磁器絵付け', '景徳鎮では磁器は単なる器ではなく、キャンバスでもあります。名匠たちは極細の筆で山水や鳥、詩の一節を描き込みます。釉下彩や釉上彩といった技法は代々受け継がれ、名匠の署名が入った作品は、絵画と同じように美術品として収集されています。'),
  'jian/jinggang': ('井岡山', '霧に包まれた井崗山（せいこうざん）は、1927年に中国革命最初の農村根拠地が築かれた場所です。今では「レッドツーリズム（革命史跡観光）」の中心地となったこの山々は、歴史的な史跡に加え、滝や竹林、峰々の下に広がる雲海で自然愛好家をも迎えています。'),
  'jian/torch': ('革命の火種', '「星星之火、以て原を燎くべし（一つの火花が草原を燃やす）」という言葉は、革命がこの山々から全国へ広がったさまを表しています。井崗山一帯の記念碑や博物館、保存された司令部跡が当時の苦難の闘いを伝え、歴史の道をたどるハイカーたちは雄大な山の景色を楽しみます。'),
  'jian/academy': ('白鷺洲書院', '贛江（かんこう）の中州に宋の時代に創設された白鷺洲書院（はくろしゅうしょいん）は、何世紀にもわたり学者を育ててきました。民族的英雄の文天祥（ぶんてんしょう）もここで学んだ一人です。川に四方を抱かれた静かな中庭は、中国の伝統的な学問の世界を伝える優雅な記憶です。'),
  'jian/pine': ('井岡山の松', '井崗山の険しい斜面に根を張る松は、霧にも風にも負けずまっすぐに立っています。むき出しの岩にしがみついて育つこの木々は、たくましさと希望の象徴とされています。日の出のころ、雲海から松のシルエットが浮かび上がる光景は、忘れがたい美しさです。'),
  'nanping/wuyi': ('武夷山', '深紅の断崖と緑の渓谷、その間を縫って流れる澄んだ渓流を持つ武夷山（ぶいさん）は、自然と文化の両方でユネスコ世界遺産に登録されています。古代の摩崖石刻や段々畑の茶園、朱熹（しゅき）の書院の跡は、この山々を中国思想史の一部にもしています。'),
  'nanping/rocktea': ('武夷岩茶', '武夷山の断崖のミネラル豊かな土壌で育つ「岩茶（がんちゃ）」と呼ばれるウーロン茶の頂点に立つのが、大紅袍（だいこうほう）、すなわち「大きな紅の衣」です。岩壁に生える樹齢数百年の母樹から摘まれた茶葉は伝説的な高値をつけ、その焙煎の効いた深い味わいは茶の世界で深い敬意を集めています。'),
  'nanping/bambooraft': ('九曲渓の竹筏', '九曲渓（きゅうきょくけい）は、武夷山の赤い断崖の間を九つの大きな曲がりで流れる渓流です。船頭が竹竿で操る竹いかだに乗った旅人は、断崖の高みに納められた謎めいた古代の船棺（ふなひつぎ）のそばを漂いながら、曲がるたびに移り変わる景色を眺めます。'),
  'nanping/scholar': ('朱熹', '朱子学の大成者である朱熹（しゅき）は、生涯の多くを武夷山の周辺で過ごし、この地に書院を開いて弟子たちを育てました。儒教思想を新たに解釈したその教えは、何世紀にもわたって中国と東アジアの教育や科挙制度を形づくりました。'),
  'shenzhen/skyscraper': ('超高層ビル群', '40年前には漁村だった深圳は、中国初の経済特区に指定されて以来、超高層ビルの森へと変貌しました。雲を突く平安金融センターを頂くスカイラインは改革の時代のスピードの象徴で、一夜にしてフロアが積み上がる様子は「深圳速度」という言葉で語られます。'),
  'shenzhen/chip': ('テックシティ', '華強北の電気街では、チップや基板、ドローンの部品が屋台から屋台へと流れていきます。テンセント、ファーウェイ、DJIといった巨大企業もこの街で育ちました。「中国のシリコンバレー」深圳では、アイデアが数日でプロトタイプになります。ここはハードウェア・スタートアップの世界の首都なのです。'),
  'shenzhen/miniature': ('世界の窓', 'テーマパーク「世界の窓」は、エッフェル塔からピラミッドまで、世界の有名建築のミニチュアを一堂に集めています。午後のひとときで大陸から大陸へと歩いて渡ることができ、園内の「エッフェル塔」は夜になるとライトアップされ、深圳の遊び心と大きな野心を象徴しています。'),
  'shenzhen/mangrove': ('深セン湾', '超高層ビルの足元に広がる深圳湾のマングローブ林は、渡り鳥たちの重要な中継地です。シラサギやシギ・チドリが干潟で餌をついばむかたわら、海辺の公園の遊歩道は、自然と大都市が肩を並べるめったにない眺めを市民に届けてくれます。'),
  'xian/terracotta': ('兵馬俑', '秦の始皇帝の陵墓を守る数千体の兵馬俑は、1974年、井戸を掘っていた村人たちによって偶然発見されました。兵士の顔はひとつとして同じものがありません。静かに整列した軍団は、不老不死を求めた皇帝の権力を今に伝え、「世界第八の不思議」とも呼ばれています。'),
  'xian/citywall': ('西安城壁', '西安の明代の城壁は中国でもっとも完全に残る城壁で、その堂々たる壁体は旧市街を切れ目のない長方形に囲んでいます。自転車を借りて城壁の上を一周するのは西安の定番体験。物見櫓から眺めると、現代の街と古代の都がひとつの風景に収まります。'),
  'xian/drumtower': ('鐘楼', '街のちょうど中心にそびえる明代の鐘楼は、古都の心臓部を示す目印で、かつてはその鐘が一日の時刻を告げていました。隣に立つ鼓楼と、その裏手に広がる回民街のグルメストリートとともに、西安の夜でもっとも活気ある広場を形づくっています。'),
  'xian/roujiamo': ('肉夾饃', '香辛料とともに何時間も煮込んだ肉を、パリッと焼いたパンに挟む——だから肉夹馍（ロウジアモー）は「中国のハンバーガー」と呼ばれます。陝西の屋台料理を代表するこの一品は、シルクロードの都の慌ただしさにぴったり。片手で持てて、二口で千年の味の伝統へとつながります。'),
  'suzhou/garden': ('蘇州古典園林', '蘇州の古典園林は、築山や池、東屋によって小さな空間に自然を再現した匠の傑作で、名園の数々はユネスコ世界遺産に登録されています。窓のひとつひとつが絵画のように切り取られており、園内を歩けば、一歩ごとに絵の変わる巻物を広げていくような気分になります。'),
  'suzhou/watertown': ('水郷の町', '運河と、弓なりに反った石橋、白壁の家々を持つ蘇州は「東洋のヴェネツィア」と呼ばれます。平江路のような古い通りでは、水が家々の玄関のすぐ前を流れていきます。小舟で滑るように進めば、茶館から琵琶の音色や地元の弾き語りが聞こえてくるでしょう。'),
  'suzhou/embroidery': ('蘇州刺繍', '蘇州刺繍（蘇繍）は、髪の毛より細い糸で絹に施される千年の歴史を持つ工芸です。最高の名手は、一枚の布の裏と表に異なる図柄を刺すことさえできます。猫の毛の艶や魚の鱗のきらめきを針でとらえるこの芸術は、この街の忍耐と繊細さの象徴です。'),
  'suzhou/kunqu': ('昆曲', 'あらゆる中国伝統演劇の母とされる崑曲（こんきょく）は、蘇州の周辺で生まれました。流れる水のような旋律と、優雅に様式化された身のこなしで知られています。ユネスコの無形文化遺産に登録されたこの芸術は、今も庭園の東屋や小さな劇場で演じられ続けています。'),
  'kunming/stoneforest': ('石林', '何百万年もかけて水に削られた巨大な石灰岩の柱が、昆明の近くに「石林」と呼ばれる迷宮を作り上げています。地元のサニの人々はこの岩々をアシマ伝説で語ります。石に姿を変えた美しい娘は、今もひとつの有名な岩柱の姿で訪れる人々を迎えているのです。'),
  'kunming/springcity': ('春城', '標高の高い雲南高原の温和な気候のもと、冬はやわらかく夏は涼しい昆明は、花の絶えない「春城（春の街）」と呼ばれています。アジア最大級の花市場を擁し、街角でさえ摘みたての花束が売られています。'),
  'kunming/seagull': ('ユリカモメ', '毎年冬になると、シベリアから飛来する何千羽ものユリカモメが、昆明の湖畔や公園を白く染めます。手からカモメに餌をやるのは市民に愛される冬の習わしで、カモメたちの帰還は、まるで季節の訪れの知らせのように祝われます。'),
  'kunming/ricenoodle': ('過橋米線', '過橋米線（かきょうべいせん）は雲南を代表する名物料理です。煮えたぎるスープが食卓に運ばれ、細い米麺と具材が目の前で椀に加えられていきます。伝説によれば、島の橋を渡って勉学中の夫に食事を運んでいた妻が、スープを熱く保つこの方法を考え出したのだそうです。'),
  'jinan/spring': ('泉城', '済南では、地下水が街のど真ん中で湧き上がって地表に顔を出します。72の名泉の中でいちばんの人気者は、こんこんと湧く趵突泉（ほうとつせん）です。「泉城」では古い町並みの路地にさえ澄んだ水が流れ、地元の人々は今も泉の水でお茶を淹れることを誇りにしています。'),
  'jinan/daminglake': ('大明湖', '泉の水に育まれた大明湖は、柳と蓮に囲まれた都会のオアシスです。夏には咲き誇る蓮の間を小舟が行き交い、湖畔の東屋や茶館は、中国文学にも記された済南のゆったりとして優雅な暮らしのリズムを今に伝えています。'),
  'jinan/buddhamountain': ('千仏山', '千仏山の斜面には、何世紀にもわたって数百体の仏像が彫られてきました。最古の磨崖仏は隋の時代にまでさかのぼります。山道を登る人々は、石の龕（がん）に納まった仏像と、山頂から見渡す泉の都・済南の大パノラマの両方を楽しむことができます。'),
  'jinan/poet': ('李清照', '中国文学史上最高の女性詩人とされる李清照は、宋の時代にこの泉の都で生まれました。繊細な哀愁をたたえた詞（し）の数々は、愛と流浪と喪失を歌っています。趵突泉のかたわらに立つ記念堂は、彼女の詩句を生んだ水音のする世界を今に伝えています。'),
  'ningbo/library': ('天一閣', '明代に創設された天一閣は、アジアに現存する最古の私設図書館で、創設者は書物をこよなく愛した役人でした。貴重な写本を湿気と火災から守るため、庭園と池、そして誰が入れるかを定めた厳格な家訓を備えた、まさに「書物の神殿」として設計されたのです。'),
  'ningbo/port': ('寧波舟山港', '寧波舟山港は貨物取扱量で世界一の港であり、巨大なコンテナ船とクレーンが海岸線を機械の森に変えています。寧波の海洋の歴史ははるかに古く、この街は古代の海のシルクロードの出発点のひとつでした。'),
  'ningbo/tangyuan': ('湯円', '寧波風の湯円（タンユエン）は、黒ごま餡を包んだつるりとした白玉団子です。かじると温かい餡が小さなサプライズのようにとろりと流れ出します。元宵節（ランタン祭り）を代表するこの甘味は、その丸い形で家族の団らんと再会を象徴しています。'),
  'ningbo/seafood': ('海鮮料理', '東シナ海に面した寧波の食卓は、海の恵みで整えられます。キグチ、カニ、貝類がこの料理の土台です。地元の味覚は「塩味と新鮮さ」のバランスを何より大切にし、魚そのものの味を消さないシンプルな蒸し料理や浅い塩漬けが、この食文化の真骨頂です。'),
  'shijiazhuang/bridge': ('趙州橋', '隋の時代に名匠・李春が建造した趙州橋は、世界最古のオープンスパンドレル式石造アーチ橋です。約1400年ものあいだ洪水や地震に耐えてきたこの優美なアーチは、中国土木技術の古典的傑作として教科書でも語られています。'),
  'shijiazhuang/clifftemple': ('蒼岩山', '蒼岩山では、ふたつの断崖の間に架かる石橋の上に、宙に浮かぶように寺院が建っています。中国でもっとも印象的な風景のひとつであるこの建物へは、緑の谷から続く急な石段を登って向かいます。映画「グリーン・デスティニー」のラストシーンの舞台にもなりました。'),
  'shijiazhuang/redbase': ('西柏坡', '石家荘近郊の西柏坡（せいはくは）村は、内戦最終期の革命司令部でした。新中国建国の計画は、この土壁の中庭で練られたのです。今では「レッドツーリズム（革命聖地巡り）」の聖地のひとつとなり、素朴な農家の家々が歴史の大きな決断の証人となっています。'),
  'shijiazhuang/pharma': ('医薬の街', '石家荘は中国最大級の医薬品生産拠点で、特に抗生物質と原薬の生産により「薬の都」と呼ばれています。鉄道の要衝として発展したこの若い省都は、その工業都市としての顔を、製薬と現代的なものづくりで彩っています。'),
  'taiyuan/jincitemple': ('晋祠', '太原の郊外にある晋祠（しんし）は、聖なる泉と古木の柏、そして宋代の侍女像を擁する、華北でもっとも優美な廟園です。木造の聖母殿に並ぶ像はひとつひとつ表情が異なり、まるで千年ものあいだ、ひそひそと語り合ってきたかのようです。'),
  'taiyuan/coalcart': ('石炭の都', '山西の山々には石炭の鉱脈が縦横に走り、中国のエネルギーの多くがここから掘り出されます。太原はその富の都です。採炭業はこの街に工業と鉄道、重機械の文化をもたらしました。今日、街は石炭の遺産をクリーンエネルギーと釣り合わせようと歩みを進めています。'),
  'taiyuan/vinegar': ('山西老陳酢', '山西省の熟成老陳酢は、コーリャンや穀物をじっくり発酵させて造られ、深い色と燻したような酸味で食卓の主役となっています。地元の人々は麺から餃子まであらゆる料理に酢を回しかけます。ここでは酢は単なる調味料ではなく、ほとんどアイデンティティそのものなのです。'),
  'taiyuan/twinpagoda': ('双塔', '街の南東に並んで立つ八角形の明代の双塔は、何世紀にもわたって変わらぬ太原のシンボルです。レンガを積み上げた塔は組積造の技の細やかさを見せ、春に周囲を彩る梅の花は、訪問のいちばんの撮影の好機を与えてくれます。'),
  'hohhot/lamatemple': ('大召寺', '明代に創建された大召寺（ダージャオ寺）はフフホトの精神的な中心で、最大の宝物は銀でできた仏像です。草原に立つチベット仏教のこの中心地は、線香の煙とマニ車、低く響く読経に包まれ、街の喧騒とはまるで別の世界を訪れる人に見せてくれます。'),
  'hohhot/dairy': ('乳業の都', '中国最大の乳業ブランドの数々はフフホトで生まれました。草原のミルクの伝統がここで近代産業に発展し、この街は「乳都（ミルクの都）」と呼ばれています。食卓ではミルクティーや乾燥チーズ、クロテッドクリームといったモンゴルの味覚が、今も工場製品と肩を並べて生き続けています。'),
  'hohhot/wrestling': ('モンゴル相撲', 'モンゴル相撲「ブフ」は、ナーダム祭の花形競技です。力士たちは刺繍入りのベストをまとい、鷲の舞を披露しながら土俵に登場します。勝者は力だけでなく優雅さでも称えられます。草原では相撲は、乗馬、弓術とともに「男の三芸」のひとつに数えられているのです。'),
  'hohhot/prairie': ('草原', 'フフホトのすぐ先には、モンゴルの大草原が地平線まで広がっています。夏には緑の海のように波打つ牧草地で、馬の群れと羊たちが草を食んでいます。ゲルに泊まる客人はミルクティーと羊肉のごちそうでもてなされ、夜には都会で忘れられた満天の星が空を埋め尽くします。'),
  'sanya/resortbeach': ('亜龍湾', '海南島の南端に位置する三亜は、中国のトロピカルリゾートの都です。亜龍湾のパウダーのような砂浜とターコイズブルーの海は、「中国のハワイ」の名にふさわしい風景です。ヤシの並ぶ海岸では一年中夏が続き、冬でも泳げる中国では数少ない海辺のひとつです。'),
  'sanya/guanyin': ('南山海上観音聖像', '南山の海上にそびえる高さ108メートルの観音像は、世界でもっとも高い女神像のひとつです。三つの顔はそれぞれ陸と海と沖合を見つめています。慈悲の女神の足元へと続く参道には、巡礼者も好奇心いっぱいの旅人も、等しく引き寄せられていきます。'),
  'sanya/diving': ('ダイビング', '温かく透き通った海を持つ三亜は、中国のダイビング天国です。蜈支洲島（ごししゅうとう）の周りのサンゴ礁は色とりどりの魚であふれています。初心者はインストラクターと一緒に浅い礁で潜り、シュノーケルだけでも、水面下に広がる熱帯の庭園をのぞき込むことができます。'),
  'sanya/coconutdrink': ('ココナッツジュース', '三亜ではココナッツが暮らしの一部です。海岸沿いでは売り子たちが山刀で採れたての実を割り、ストローを挿して手渡してくれます。冷たいココナッツウォーターは南国の暑さへの何より自然な特効薬。ミルクは地元の鶏料理やデザートを彩り、殻は手工芸品へと生まれ変わります。'),
  'yangzhou/slenderlake': ('痩西湖', '痩西湖（そうせいこ）という名は、杭州の名高い西湖への優雅なオマージュです。細長く続く水路は柳、白いアーチ橋、東屋で飾られています。清の皇帝たちが南巡の折に嘆賞したこの風景は、今日もなお一幅の水墨画のような気品を保っています。'),
  'yangzhou/friedrice': ('揚州チャーハン', '揚州チャーハンは、エビと卵とネギを米粒がぱらぱらになるまで炒め上げた黄金色の定番料理で、その名は世界中の中華料理店に生き続けています。秘訣はシンプルさにあります。米の一粒一粒を卵でコーティングし、具材は新鮮に、そして決して欲張らないことです。'),
  'yangzhou/morningtea': ('早茶', '揚州の一日は「早茶（朝のお茶）」の習わしで始まります。濃く淹れたお茶とともに、蒸したての包子、極細に刻んだ干し豆腐の和え物、スープたっぷりの小籠包が食卓に並びます。老舗の茶館ではこの朝食が何時間も続き、急いで済ませるのはほとんど無作法とされるほどです。'),
  'yangzhou/gegarden': ('個園', '裕福な塩商人が築いた個園（こえん）は、竹の葉の形にその名を由来します。この庭園でもっとも名高い趣向は、異なる石で四季を表現した築山の数々です。ほんの数歩で春から冬へと歩き渡り、古典庭園芸術の頂点を体感できるのです。'),
  'weihai/navalisland': ('劉公島', '威海の沖に浮かぶ劉公島は、清朝の近代海軍・北洋艦隊の基地でした。艦隊はここで日本海軍との戦いに敗れます。島は今、博物館と古い要塞の数々によって、中国海軍史の痛ましくも教訓に満ちた一ページを語り継いでいます。'),
  'weihai/swan': ('スワンレイク', '毎年冬、シベリアから飛来する数百羽のオオハクチョウが、威海近郊の海辺のラグーンをすみかとします。朝霧の中を滑るように進む白い鳥たちは写真家や自然愛好家を引き寄せ、村人たちはハクチョウを隣人のように大切にし、餌を与えて世話をしています。'),
  'weihai/seacucumber': ('ナマコ', '威海の冷たく清らかな海で育つナマコは、中華の食卓でもっとも珍重される海の幸のひとつです。滋養に富むとされるこの海の生き物は、特別な日のごちそうであり格式ある贈り物でもあります。沿岸に連なる養殖場は、この街の暮らしを支える大切な生業となっています。'),
  'weihai/cape': ('成山頭', '威海の東にある成山頭（せいざんとう）岬は、中国大陸が海へと突き出す最東端のひとつで、太陽はこの国をまずここで迎えます。伝説によれば、始皇帝はここまで旅をして、波の彼方にある不老不死の国を探し求めたといいます。この岬は「天の尽きる場所」とも呼ばれています。'),
  'handan/taichi': ('太極拳', '邯鄲（かんたん）近郊の城壁の町・広府鎮は、太極拳の楊式と武式が生まれた地で、伝説の達人・楊露禅もここで修行しました。朝、城壁の下や中庭でゆっくりと流れるような型を練る門下生たちが、この「柔」の武術の生きた伝統を守り続けています。'),
  'handan/congtai': ('叢台', '叢台（そうだい）は、戦国時代の強国・趙から残る遺構です。王たちが儀式や調練を眺めたこの高台は、今は公園の中心に立っています。台に登れば、古代の都として二千年以上を重ねてきた邯鄲の歴史を、高みから見渡すことができます。'),
  'handan/idiom': ('成語の街', '邯鄲は「成語のふるさと」です。1500以上もの中国の成語が、この土地で起きた出来事や物語にその起源を持ちます。もっとも有名なのは「邯鄲の歩み（邯鄲学歩）」。他人を真似るうちに自分の歩き方まで忘れてしまう人を描いたこの成語は、街の名を言葉の中に永遠に刻みつけました。'),
  'handan/ciporcelain': ('磁州窯', '磁州窯（じしゅうよう）の焼き物は、白い化粧土の上にのびのびとした筆致で描かれた黒い文様で知られています。花や魚、詩の一節が、民芸の素朴な温かみとともに器に施されるのです。宋代から続くこの伝統は、宮廷の磁器と対をなす、日常の暮らしのやきものとして生き続けています。'),
  'daqing/oilpump': ('大慶油田', '大慶油田の発見は、若き中華人民共和国を石油の輸入依存から解き放ちました。この街はまさに油井の上に築かれたと言ってよいでしょう。頭をゆっくりと上げ下げするポンプジャックは今も平原で働き続けており、大慶は中国最大の油田として歴史に名を刻みました。'),
  'daqing/oilworker': ('鉄人', '石油労働者の王進喜（おうしんき）は、凍てつく寒さの中で油井を切り開いた不屈の精神から「鉄人」の異名をとりました。掘削の泥の穴に自ら飛び込み、身体で泥漿をかき混ぜたという逸話も残っています。彼の名を冠した博物館と「鉄人精神」が、大慶の建設の伝説を今に伝えています。'),
  'daqing/reedlake': ('湿地帯', '油井の間に、驚くべき大自然が隠れています。大慶の広大な葦の湖と湿地は、ツルやハクチョウ、渡りの水鳥たちのすみかとなっているのです。秋、黄金色に染まった葦原が風に揺れるころ、この工業都市は鳥たちの楽園へと姿を変えます。'),
  'daqing/hotspring': ('温泉', '大慶の周辺では、地の底から湧き出る温かいミネラル豊富な湯が、寒さの厳しい東北の冬に癒やしの避難所を用意してくれます。林甸県は温泉の町として名を馳せており、湯気の立つ湯船でくつろぐひとときは、石油の街の厳しい気候へのやさしい答えです。'),
  'zibo/bbq': ('淄博バーベキュー', '淄博（しはく）バーベキューは「三点セット」で有名です。小さな炭火コンロ、細い串、そしてクレープのような薄餅。串の仕上げは自分で焼き、ネギとタレと一緒に薄餅で巻いて食べます。この気さくなスタイルが中国のSNSを席巻し、街の名は一夜にして全国の話題となりました。'),
  'zibo/cuju': ('蹴鞠', '世界最古のサッカーである蹴鞠（しゅうきく／ツーチュー）は、古代・斉の都の臨淄（りんし）で行われており、FIFAもここをサッカー発祥の地として認めています。革製の鞠を足で蹴り上げ続けるこの遊びは、宮廷の娯楽から軍の訓練にまで及ぶ豊かな歴史を持っています。'),
  'zibo/ceramic': ('淄博陶磁器', '淄博の窯の火は千年以上も燃え続けており、この街は華北でもっとも歴史の深い陶磁器の中心地のひとつです。日用の器から芸術磁器にまで及ぶ生産の伝統は、今日、博物館や工房で受け継がれ、陶磁器フェアには全国から作り手たちが集まってきます。'),
  'zibo/glass': ('瑠璃', '色鮮やかな溶けたガラスを手で形づくる琉璃（るり）は、光と戯れる淄博の工芸で、博山区がその歴史的な中心地として知られています。職人たちは赤熱したガラスをやっとこで引き伸ばし、曲げていきます。生まれたビーズや鳥、花瓶は、太陽の下でステンドグラスのように輝きます。'),
  'taian/mounttai': ('泰山', '五岳の筆頭である泰山は、中国でもっとも神聖な霊峰です。歴代の皇帝たちは何世紀にもわたり、天に自らの治世を告げる封禅の儀式をここで執り行いました。ユネスコ世界遺産であるこの山の岩々には詩人や書家の銘文が刻まれており、石のひとつひとつが歴史のページなのです。'),
  'taian/sunrise': ('泰山の日の出', '泰山に登る最大のごほうびは、山頂で雲海の上に昇る朝日を眺めることです。何千人もの人々が夜通し山を登り、玉皇頂で夜明けを待ちます。地平線が紅に染まった瞬間、群衆から沸き上がる歓声が、登山の疲れを一瞬で洗い流してくれるのです。'),
  'taian/stonesteps': ('十八盤', '山頂へと続くおよそ7000段の石段は、巡礼者たちが何世紀も一歩一歩登ってきた身体の試練です。もっとも険しい区間は「十八盤」と呼ばれる天への曲がり道。荷を担いで毎日この石段を上り下りする荷担ぎの人々は、この山の静かな英雄です。'),
  'taian/daitemple': ('岱廟', '山のふもとにある岱廟（たいびょう）は、皇帝たちが泰山での儀式の前に身を整え、宿泊した壮麗な建築群です。宮殿様式の本殿は、泰山の神の巡行を描いた巨大な壁画で知られ、中庭に立つ古木の柏たちは歴史の証人となっています。'),
  'lianyungang/monkey': ('花果山', '「西遊記」の主人公・孫悟空のふるさと、花果山（かかざん）はここにそびえています。水簾洞へは滝の裏側から入ることができ、岩場を歩き回る本物のニホンザルの仲間（アカゲザル）たちが、伝説と風景の境目を心地よく曖昧にしてくれます。'),
  'lianyungang/seaport': ('連雲港港', '連雲港は、ユーラシア大陸を横断する鉄道ランドブリッジの太平洋側の終着点です。ここで積み込まれた列車は中央アジアを経てヨーロッパへと走っていきます。シルクロードの東の海の玄関とされるこの港は、古代の交易路の現代版と呼ぶにふさわしい存在です。'),
  'lianyungang/mountain': ('雲台山', '雲台山の険しい峰々は、江蘇省の最高地点を擁しています。低い平野で知られるこの省にあって、この山並みは驚くべき例外です。森に覆われた斜面、寺院、海を望む尾根道を持つこの山地は、街の人々にとって自然への逃避先となっています。'),
  'lianyungang/crystal': ('水晶の街', '連雲港の東海県は、世界最大級の水晶市場のひとつを擁しています。この土地から掘り出される透きとおった水晶は、宝飾品から工業原料まであらゆる分野で活用されており、町の市場の売り台はきらきらと光る石で埋め尽くされています。'),
  'maanshan/libai': ('李白の墓', '中国最高の詩人とたたえられる李白は、晩年をこの川辺の町の周辺で過ごしました。その墓は近くの当塗（とうと）にあります。酒と月と自由を詩に変えた大詩人の足跡は記念公園に生きており、馬鞍山は誇りを込めて自らを「詩の街」と名乗っています。'),
  'maanshan/steel': ('鉄鋼の街', '馬鋼（マーガン）製鉄所は、馬鞍山を中国有数の鉄鋼基地に押し上げました。高炉は長江のほとりで何十年も煙を上げ続けています。この街は重工業の顔を詩情あふれる過去と釣り合わせています。一方には溶けた鋼、もう一方には李白の詩句があるのです。'),
  'maanshan/rivercliff': ('采石磯', '長江に垂直に切れ落ちる采石磯（さいせきき）の断崖は、この大河でもっとも詩的な眺めのひとつを見せてくれます。伝説によれば、李白はここで水面に映る月を抱こうとして川に落ち、不滅の存在となりました。断崖の東屋や小道は、今もその物語をささやいています。'),
  'maanshan/moonwine': ('李白の月と酒', '李白の詩を貫くふたつの大きなイメージ、月と酒は、馬鞍山で今も祝われています。街は彼を偲んで詩の祭典を開いてきました。川辺で杯を掲げ月を眺めることは、千年前の詩人と同じ気持ちを分かち合う、いちばん素朴な方法なのです。'),
  'longyan/tulou': ('永定土楼', '永定の山々に点在する巨大な円形の土楼（どろう）は、客家の人々が土と木で築いた城塞住宅で、ユネスコ世界遺産に登録されています。分厚い土壁の内側では数十の家族が寄り添って暮らしており、中庭から立ちのぼるかまどの煙は、何百年も続く共同生活の香りそのものです。'),
  'longyan/redmeeting': ('古田会議', '1929年、紅軍の原則と進路を定めた歴史的な古田（こでん）会議が、龍岩のこの山あいの村で開かれました。白壁の会議場は今も保存されており、村は革命史の転換点のひとつをたどろうとする人々の訪問地となっています。'),
  'longyan/hakka': ('客家文化', '戦乱を逃れて華北から南へと移り住んだ客家の人々は、「客人の家族」を意味するその名をこの旅路から得ました。龍岩の山々の中で、彼らは独自の言葉や塩焗鶏（塩蒸し鶏）のような料理、そして強い家族の絆を、何世紀にもわたって守り続けています。'),
  'longyan/mountain': ('冠豸山', '冠豸山（かんちざん）は、古代の裁判官の冠に似ているといわれる赤い岩の頂で知られています。丹霞（たんか）と呼ばれるこの紅色の岩壁は、澄んだ池と険しい渓谷に囲まれています。岩に刻まれた石段や湖上の舟遊びとともに、この山は福建南部の自然の真珠と称えられています。'),
  'sanming/danxia': ('泰寧丹霞', '福建省北西部の泰寧（たいねい）は、赤い砂岩の断崖、狭い峡谷、洞窟が広がるユネスコ世界ジオパークです。水が何百万年もかけて刻んだこの石の迷宮を船でめぐり、緋色の岩壁の間を緑の流れが滑るように進む景色を楽しめます。'),
  'sanming/shaxian': ('沙県小吃', '沙県（さけん）の素朴な料理は、安くて満足感のあるメニューで中国全土に広がった一大現象です。薄皮のワンタン、ピーナッツソースの和え麺、じっくり蒸したスープが、中国のほぼどの街角にもある沙県小吃の店で、同じ温かさで提供されています。'),
  'sanming/forest': ('緑の都', '三明（さんめい）は中国で最も森林被覆率が高い都市の一つで、山々は尾根から谷まで緑に包まれています。かつての林業の町はエコツーリズムへと舵を切り、澄んだ空気と森の遊歩道を誇る「緑の都」の称号を胸を張って掲げています。'),
  'sanming/goldenlake': ('金湖', '金湖（きんこ）は、泰寧の赤い丹霞（たんか）の崖の間に広がる大きなダム湖です。遊覧船は狭い水の峡谷を抜け、切り立つ岩壁や岩窟に建てられた甘露寺（かんろじ）のそばを進みます。水と石が出会う、めったに見られない絶景です。'),
  'ningde/mudflat': ('霞浦の干潟', '霞浦（かほ）の海岸では毎日潮が引くと、移ろう光にきらめく広大な干潟が姿を現します。海藻の養殖場、並んだ竹竿、浅瀬で働く漁師たちの姿が、この海岸を世界的に有名な写真家たちの集いの場に変えました。'),
  'ningde/whitetea': ('福鼎白茶', '福鼎（ふくてい）は中国白茶のふるさとです。銀色の産毛をまとった新芽は萎凋と乾燥だけで仕上げられ、決して火入れされません。「一年は茶、三年は薬、七年は宝」ということわざは、この繊細なお茶が年を重ねるほど価値を増すことを物語っています。'),
  'ningde/taimu': ('太姥山', '太姥山（たいぼさん）は、丸みを帯びた花崗岩の峰、狭い岩の裂け目、洞窟の通路を持ち、海を見下ろすようにそびえています。古くから「海上の仙境」と呼ばれ、巨岩の間を縫う小道を登れば、霧と海が出会う絶景の展望台にたどり着きます。'),
  'ningde/croaker': ('イシモチ', '寧徳（ねいとく）の穏やかな三都澳（さんとおう）の入り江は、中国最大のキグチ（大黄魚）養殖の拠点です。浮かぶ生け簀の養殖場は海の上にまるで一つの村をつくり、繊細な白身のこの魚はシンプルに蒸されて福建の食卓の主役となります。'),
  'shaoguan/redcliff': ('丹霞山', '丹霞山（たんかざん）は、世界中の「丹霞地形」という名の由来となった赤い砂岩の山塊で、ユネスコ世界遺産に登録されています。風と水が刻んだ塔や柱は夕日に燃えるように輝き、曲がりくねった遊歩道や川下りでこの赤い迷宮を探検できます。'),
  'shaoguan/chantemple': ('南華寺', '韶関（しょうかん）近郊の南華寺（なんかじ）は、禅宗の六祖・慧能（えのう）がその教えを広めた場所です。およそ千五百年の歴史を持つ南宗禅の聖地であり、今も巡礼者たちが線香の煙の中で祖師の足跡をたどっています。'),
  'shaoguan/ancestor': ('珠璣巷', '南雄（なんゆう）の珠璣巷（しゅきこう）は、宋代に北から移住してきた一族が南へ下る前に滞在した中継地でした。今日、数百万人の広東の人々がこの狭い石畳の路地に家系のルーツを求め、毎年先祖の名を探しに訪れています。'),
  'shaoguan/yaodance': ('ヤオ族', '韶関の山あいの県に暮らすヤオ族は、目を奪う刺繍の衣装と長鼓（ちょうこ）の踊りで知られています。収穫祭には太鼓の音が谷にこだまし、刺繍の文様は文字を持たない言葉のように一族の歴史を代々伝えています。'),
  'zhanjiang/oyster': ('湛江牡蠣', '湛江（たんこう）の温かく澄んだ南の海で育つカキは、大ぶりでミルクのようにふっくらしています。夜になると屋台でニンニクと油をのせて炭火で焼かれ、潮の香りのこの味は、街のナイトライフに欠かせない習わしとなっています。'),
  'zhanjiang/navy': ('軍港', '深く守られた天然の良港を持つ湛江は、中国海軍の南海艦隊の母港です。かつて広州湾（こうしゅうわん）の名でフランスの租借地だったこの港町は、今では南シナ海へと開く国の戦略的な玄関口となっています。'),
  'zhanjiang/mangrove': ('マングローブ林', '湛江の海岸に広がるマングローブ林は、中国最大のマングローブ保護区です。潮の満ち引きとともに満ちては干くこの塩水の森にはシラサギやトビハゼ、カニが暮らし、絡み合った根は嵐から海岸を守り、稚魚たちの天然のゆりかごにもなっています。'),
  'zhanjiang/donghai': ('東海島', '湛江沖の東海島（とうかいとう）は、何キロも途切れることなく続く砂浜で有名です。安定した風はサーファーたちを引き寄せ、島はまた、数十人が肩を組んで一匹の龍になる伝統の「人龍舞」でも知られています。'),
  'maoming/lychee': ('ライチの都', '茂名（もめい）は世界有数のライチの産地で、初夏には丘が赤い果実で染まります。古代にはこの地のライチが皇帝の宮廷への貢ぎ物として届けられ、果樹園の樹齢数百年のライチの木は、今も実をつけ続けています。'),
  'maoming/refinery': ('石油化学コンビナート', '茂名は1950年代にオイルシェールの加工で発展した工業都市で、今日では華南最大級の石油化学コンビナートを擁しています。製油所やエチレン工場が、農業の豊かなこの緑の地域に力強い経済の背骨を与えています。'),
  'maoming/ladyxian': ('冼夫人', '六世紀に生きた冼夫人（せんふじん）は、南方の諸民族を平和のうちにまとめた賢明な女性指導者でした。茂名とその周辺には彼女を祀る廟が数百もあり、毎年の記念祭は、千五百年近く続く敬愛の証となっています。'),
  'maoming/seaside': ('中国第一灘', '「中国第一灘」とうたわれる茂名の海岸は、黄金色の砂が何キロも続きます。海岸沿いに植えられたモクマオウの林が風を防ぐ緑のカーテンとなり、家族連れは海水浴を楽しんだあと、海鮮レストランで一日を締めくくります。'),
  'zhaoqing/sevenstar': ('七星岩', '北斗七星を思わせる配置で、七つの石灰岩の峰が星湖（せいこ）の上にそびえています。岩の内部は洞窟と何世紀にもわたる刻文で満ち、湖畔の堤を散策すれば、「広東の桂林」と呼ばれる理由を実感できます。'),
  'zhaoqing/inkstone': ('端渓硯', '文房四宝のうち、最も名高い硯（すずり）が肇慶（ちょうけい）の端渓硯（たんけいけん）です。唐代からこの地の石切り場で採られてきた紫の石は、彫り師の手で芸術品に生まれ変わります。良い端渓硯は墨を乾きにくく保ち、筆をやさしく扱ってくれるのです。'),
  'zhaoqing/dinghu': ('鼎湖山', '鼎湖山（ていこざん）は、1956年に指定された中国初の自然保護区です。手つかずの亜熱帯雨林、滝、慶雲寺（けいうんじ）を擁するこの山は、都会の人々が「天然の酸素バー」と親しみを込めて呼ぶ、涼しい安らぎの場です。'),
  'zhaoqing/songwall': ('宋代城壁', '肇慶の城壁は宋代に築かれ、その周囲はほぼ完全な形で今日まで残っています。煉瓦の層には歴代王朝の修復の跡が読み取れ、城壁の上を歩くことは、およそ千年に及ぶ都市の歴史をひとめぐりする旅なのです。'),
  'huizhou/westlake': ('恵州西湖', '恵州西湖（けいしゅうせいこ）は、柳の並ぶ堤、石橋、小島が織りなす優雅な古典的景観です。この地に流された大詩人・蘇東坡（そとうば）は湖を詩に詠んで不朽のものとし、湖畔の堤は今も彼の名を冠しています。'),
  'huizhou/luofu': ('羅浮山', '羅浮山（らふさん）は華南で最も神聖な道教の山の一つで、何世紀にもわたり隠者や錬丹術師たちをその峰々に引き寄せてきました。薬草で名高い森には、寺院や湧き水、そして雲へと続く登山道があなたを待っています。'),
  'huizhou/alchemy': ('葛洪の錬丹術', '晋代の錬丹術師で医師の葛洪（かっこう）は、羅浮山にこもって丹薬を練り、医学書をここで著しました。彼が古い医書に記した青蒿（クソニンジン）についての一節は、何世紀も後に現代のマラリア治療薬の発見にひらめきを与えたのです。'),
  'huizhou/xunliao': ('巽寮湾', '巽寮湾（そんりょうわん）は、浅いターコイズブルーの海と長く続く淡い色の砂浜が魅力で、広東海岸で人気のリゾート地です。かつて漁村だった町では新鮮な海の幸が味わえ、穏やかな海は子ども連れの家族にぴったりです。'),
  'meizhou/weilongwu': ('囲龍屋', '梅州（ばいしゅう）は、世界中に散らばる客家（はっか）の人々の心のふるさととされています。丘に寄り添う馬蹄形の囲龍屋（いりゅうおく）は大きな一族を一つ屋根の下に集め、その中庭では今も一族の祭りが祝われています。'),
  'meizhou/saltchicken': ('塩焗鶏', '塩焗鶏（えんきくどり）は、客家料理で最も有名な定番です。紙で包んだ丸鶏を熱した粗塩に埋めて火を通します。塩は肉を乾かすどころか旨みを閉じ込め、生姜の香る絹のように柔らかな味わいを生み出すのです。'),
  'meizhou/football': ('サッカーの郷', '梅州は近代サッカーが中国で最も早く根づいた土地の一つで、「中国サッカーのゆりかご」と呼ばれています。伝説のストライカー李恵堂（りけいどう）はこの地に生まれ、村のグラウンドからプロクラブまで、その情熱は今も生き続けています。'),
  'meizhou/plum': ('梅の花', '梅州の名は「梅」の字に由来し、街には梅江（ばいこう）、すなわち梅の川が流れています。冬の寒さの中で咲く梅の花は、粘り強く勤勉な客家の人々の精神の象徴とされ、街のいたるところでモチーフとして目にすることができます。'),
  'jiangmen/diaolou': ('開平楼閣', '開平（かいへい）の田園にそびえる碉楼（ちょうろう）は、20世紀初頭に海外から帰郷した移民たちによって建てられました。盗賊や洪水に備えた要塞のようなこの住居は、西洋の円柱と中国の屋根を融合させており、今日ではユネスコ世界遺産となっています。'),
  'jiangmen/qiaoxiang': ('華僑の郷', '江門（こうもん）と周辺の五邑（ごゆう）地域は、世界に散らばる数百万の華僑の故郷です。南北アメリカから東南アジアに広がるこの人々は故郷に学校や道路、邸宅を寄贈し、街は今も東洋と西洋が溶け合う街並みで知られています。'),
  'jiangmen/chenpi': ('陳皮', '新会（しんかい）のミカンの皮「陳皮（ちんぴ）」は、天日で干し、何年も寝かせて熟成させてから使われます。広東料理に深い香りを添え、伝統医学でも重宝されます。よく熟成した陳皮は、まるで年代物のワインのように珍重されるのです。'),
  'jiangmen/birds': ('小鳥天堂', '新会の「小鳥天堂」は、枝から根を下ろして小さな島全体を覆った、たった一本の巨大なガジュマルです。何千羽ものシラサギや水鳥がここをねぐらとし、作家・巴金（ぱきん）の名随筆が、この緑の島を中国中に愛される存在にしました。'),
  'yangjiang/knife': ('刃物の都', '陽江（ようこう）は中国の刃物とハサミの都で、国内の包丁の大部分がこの街の工房や工場から生まれます。何百年もの鍛冶の伝統が現代の鋼鉄技術と融合し、地元ブランドは世界のキッチンへと届いています。'),
  'yangjiang/shipwreck': ('南海一号', '南海一号（なんかいいちごう）は、海のシルクロードで沈み、何百年も海底に眠っていた宋代の貿易船です。船は丸ごと引き揚げられて海陵島（かいりょうとう）のガラス水槽を備えた博物館に移され、船倉からは数万点の磁器や貴重品が姿を現しました。'),
  'yangjiang/hailing': ('海陵島', '海陵島は、三日月形の大角湾（だいかくわん）と柔らかな砂浜を持つ、広東で最も愛される海のリゾート島の一つです。昼は波間で泳ぎ、夜は漁港から届く新鮮な海の幸を味わえます。島はまた、南海一号の沈没船博物館も擁しています。'),
  'yangjiang/kite': ('凧の街', '陽江は、北の濰坊（いぼう）と並ぶ中国二大凧の都の一つに数えられています。竹の骨組みの伝統凧は何世代にもわたり手作りされ、毎年秋の重陽節（ちょうようせつ）には、空が色とりどりの翼で埋め尽くされます。'),
  'qingyuan/rafting': ('清遠ラフティング', '山から流れ下る激流を抱く清遠（せいえん）は、中国で「ラフティングのふるさと」と呼ばれています。夏には何千人もの人々が泡立つコースをボートで下り、谷あいの涼しい森や岩のプールは、都会の暑さからの絶好の逃げ場となります。'),
  'qingyuan/chicken': ('清遠鶏', 'まだら模様の羽を持つ清遠の地鶏は、骨が細く味わい深く、広東料理で最も求められる鶏です。放し飼いで育つこの品種は、シンプルに茹でて生姜とネギのソースで供されることが多く、その素朴さこそが品質の証なのです。'),
  'qingyuan/hotspring': ('温泉', '清遠の山あいの谷から湧くミネラル豊富な温泉は、この街を広東の温泉の中心地にしました。露天の湯から湯気が立ちのぼるかたわらで竹林がさやさやと鳴り、広州から訪れる週末の行楽客たちが、ここで疲れを癒やしていきます。'),
  'qingyuan/yaoterrace': ('ヤオ族の棚田', '連南（れんなん）のヤオ族の村々では、棚田が山の斜面を一段また一段と覆っています。何世紀にもわたり手作業で築かれた棚田は、春には水鏡に、秋には黄金の階段に変わり、その間には古いヤオ族の村々が今も息づいています。'),
  'chaozhou/guangjibridge': ('広済橋', '韓江（かんこう）に架かる広済橋（こうさいきょう）は、宋代に建設が始まり、中央部が横並びにつながれた舟でできている、類まれな橋です。この浮橋の部分は毎日開いて船を通し、その仕組みから中国四大古橋の一つに数えられています。'),
  'chaozhou/woodcarving': ('潮州木彫', '潮州（ちょうしゅう）の金漆木彫（きんしつもくちょう）は、一枚の板に幾重もの場面を彫り込む伝説的な工芸です。漁網から劇の英雄まであらゆる細部が精緻に刻まれ、金箔をまとった作品は寺院や邸宅をきらめきで満たしています。'),
  'chaozhou/chaoxiu': ('潮州刺繍', '潮州刺繍は広東刺繍の中でも最も華麗な一派で、金糸銀糸を詰め物の上に刺して、立体的な浮き彫りのような効果を生み出します。龍や鳳凰は布から飛び出しそうな迫力で、婚礼衣装や伝統劇の衣装を飾り続けてきました。'),
  'chaozhou/kaiyuan': ('開元寺', '唐の開元（かいげん）年間の738年に創建されたこの寺は、その年号を今も名に留めています。千年以上絶えることなく参拝が続く境内では大きな香炉が煙をくゆらせ、堂内は潮州木彫の最高傑作で飾られています。'),
  'jieyang/citygate': ('進賢門', '進賢門（しんけんもん）、すなわち「賢者を迎える門」は、古都・掲陽（けいよう）に残る優美なシンボルです。幾重にも軒を重ねた木造の楼閣は町の堀を見下ろし、その名には、賢く徳のある人々を迎え入れたいという街の願いが込められています。'),
  'jieyang/jade': ('翡翠の都', '掲陽に属する陽美（ようび）の町は、中国最大級のヒスイの加工・取引の中心地です。ミャンマーから届いた原石のヒスイがここで切られ、彫られ、磨かれます。市場の路地では、職人たちが石の中に隠れた緑を、まるで賭けのように読み取るのです。'),
  'jieyang/jieyanglou': ('掲陽楼', '掲陽楼（けいようろう）は、伝統的な反り屋根と堂々たる姿で古代建築を現代によみがえらせたモニュメントです。内部では文化展示が催され、この楼は、潮汕（ちょうさん）の人々が自らのルーツに抱く誇りを石と木に刻んだ姿なのです。'),
  'jieyang/beefbroth': ('潮汕牛肉鍋', '潮汕の牛肉スープと火鍋は、肉の新鮮さに捧げられた料理です。牛のどの部位にもそれぞれ名前があり、澄んだ煮え立つスープの中で、秒単位で計られる時間だけ火を通します。沙茶（サーチャー）ソースを添えて味わう、この簡素さの中の熟練の技こそが地方の誇りです。'),
  'yunfu/marble': ('石材の王国', '雲浮（うんふ）は中国の石材加工の都として知られ、大理石や花崗岩が何世代にもわたってこの街で切られ、磨かれてきました。幹線道路沿いに並ぶ何千もの工房がカウンター材や彫刻、外装材を世界中に送り出しており、石はまさにこの街の糧なのです。'),
  'yunfu/patriarch': ('六祖恵能', '禅宗の六祖・慧能（えのう）は、雲浮に属する新興（しんこう）に生まれ、晩年をここで過ごしました。彼をたたえて建てられた国恩寺（こくおんじ）は巡礼者が集う静かな聖地です。木こりの少年から悟りを開いた祖師へと至る彼の物語は、この地から始まったのです。'),
  'yunfu/tianlu': ('天露山', '天露山（てんろさん）は、雲へと伸びる尾根と茶畑に包まれた斜面を持つ、雲浮の緑の王冠です。朝にはしばしば谷が雲海で満たされ、日の出を目指して登るハイカーたちは、霧の中から立ち上がる峰々の絶景で報われます。'),
  'yunfu/xijiang': ('西江', '西江（せいこう）は珠江（しゅこう）水系の本流で、華南で最も往来の激しい水路の一つです。貨物船は昼夜を問わず雲浮の前を行き交い、この川は、石材や農産物を広州へ、そして世界へと運ぶ命の動脈であり続けています。'),
  'liuzhou/luosifen': ('螺蛳粉', '柳州（りゅうしゅう）のタニシ麺「螺蛳粉（ルオスーフェン）」は、タニシを煮込んだスープと、強烈な香りの発酵タケノコで知られています。その匂いは遠くからでも賛否を呼びますが、一度味わえばやみつきになる人が続出。インスタント麺になったこのご当地グルメは、中国全土そして世界を席巻しました。'),
  'liuzhou/autocity': ('自動車の街', '柳州は広西（こうせい）の工業の心臓部で、中国の主要な自動車生産拠点の一つです。この街で造られる小型で手頃な電気自動車は街の風景の象徴となり、狭い駐車スペースにもすっと収まるこの小さな車を、地元の人々は心から愛用しています。'),
  'liuzhou/karst': ('柳江のカルスト地形', '柳江（りゅうこう）は帯のように街をぐるりとめぐり、その周囲には石灰岩の峰々がそびえています。この大きな湾曲から、柳州は「急須の街」というあだ名を得ました。工業都市のただ中で、川辺の公園とカルストの峰々が驚くほどの自然美を見せてくれます。'),
  'liuzhou/liuhou': ('柳宗元', '唐代の大文学者・柳宗元（りゅうそうげん）は、流された地・柳州で長官を務め、井戸を掘らせ、貧しい人々を守りました。街の中心の柳侯公園（りゅうこうこうえん）には彼を祀る祠があり、この詩人は、晩年を過ごしたこの街と分かちがたく結びついています。'),
  'wuzhou/gemstone': ('宝石の街', '梧州（ごしゅう）は世界の人工宝石の都で、合成ジルコニアの大部分が、この川辺の街の工房でカットされ磨かれています。熟練の指先が小さな石に幾十ものファセットを刻み、きらめく石はここから世界の宝飾市場へと散らばっていきます。'),
  'wuzhou/liubaotea': ('六堡茶', '梧州の六堡茶（ろっぽちゃ）は、年月をかけて熟成し、まろやかになる黒い発酵茶です。かつて川船で東南アジアの鉱山労働者のもとへ運ばれ、湿った気候で体を整えると信じられていました。古い年代物の茶籠は、今ではコレクターたちの垂涎の的です。'),
  'wuzhou/turtlejelly': ('亀苓膏', '梧州は、薬草から作られる黒いゼリー「亀苓膏（きれいこう）」のふるさととされています。ほのかに苦いこのゼリーは、蜂蜜で甘みをつけて冷やして食べられます。蒸し暑い南方の夏に体の「内なる熱」を取り去ると信じられてきた、涼をとる伝統なのです。'),
  'wuzhou/dragonmother': ('龍母廟', '西江のほとりに立つ龍母廟（りゅうぼびょう）は、川の民の守り神とされる女神に捧げられています。伝説によれば、龍母は五匹の龍を我が子として育て、人々を洪水から守りました。祭りの日には、廟は線香の煙と願いのリボンで満たされます。'),
  'beihai/silverbeach': ('銀灘', '北海（ほっかい）の銀灘（ぎんたん）は、その名の通り、石英を豊富に含む真っ白な砂が太陽の下で銀色に輝きます。「天下第一灘」とたたえられる海岸は何キロも続き、遠浅で温かい海は、泳ぐにも散歩するにも果てしない空間を与えてくれます。'),
  'beihai/pearl': ('真珠の街', '北海に属する合浦（ごうほ）は漢代から真珠で名高く、その「南珠」は宮廷に献上される最も貴重な貢ぎ物の一つでした。「珠、合浦に還る」という故事成語はこの海岸で生まれ、今日も真珠養殖場や宝飾市場がその伝統を受け継いでいます。'),
  'beihai/weizhou': ('潿洲島', '北海沖の潿洲島（いしゅうとう）は、中国で最も若い火山島として知られています。溶岩が形づくった黒い断崖、サンゴ礁、バナナ畑が島を取り囲み、19世紀に宣教師が建てた石造りのカトリック教会は、この島いちばんの意外な見どころです。'),
  'beihai/oldstreet': ('老街', '北海の老街（ラオジエ）には、19世紀末に港が対外貿易に開かれた頃に建てられたアーケード式の騎楼（きろう）建築が並んでいます。アーチの連なるファサードには東南アジアやヨーロッパの面影が漂い、通りは今も、牡蠣オムレツの屋台や旧領事館の名残の中に往時をとどめています。'),
  'qinzhou/nixingpottery': ('坭興陶', '欽州（きんしゅう）の坭興陶（でいこうとう）は、釉薬を使わずに焼かれるにもかかわらず、窯の中でひとりでにブロンズや紅、紫の色合いをまといます。川の両岸から採った粘土を混ぜ合わせて作るこの工芸は、中国四大名陶の一つに数えられています。'),
  'qinzhou/dolphin': ('シナウスイロイルカ', '欽州の三娘湾（さんじょうわん）は、希少なシナウスイロイルカの最もよく知られた生息地の一つです。年を重ねるとピンク色に変わるこの優雅な海の哺乳類は観光船のそばに姿を見せ、湾の人々は、「海のパンダ」と呼ぶイルカを誇りをもって守っています。'),
  'qinzhou/oysterfarm': ('欽州の養殖カキ', '欽州の浅く栄養豊かな茅尾海（ぼうびかい）は、中国最大級のカキの稚貝の産地です。海面はずらりと並ぶ浮き筏で覆われ、大粒で身の詰まった収穫はこの街を南方のカキの都にしています。祭りの季節、焼き網の火が消えることはありません。'),
  'qinzhou/general': ('馮子材将軍', '清の将軍・馮子材（ふうしざい）は、高齢にもかかわらず軍に復帰し、ベトナム国境の鎮南関（ちんなんかん）で侵略に対する歴史的勝利を収めました。故郷の欽州では旧居が博物館として保存され、その名は祖国防衛の象徴として語り継がれています。'),
  'guigang/lotus': ('蓮の街', '貴港（きこう）は中国で「蓮の街」と呼ばれ、夏には周囲の池や田んぼがピンクと白の花で覆われます。レンコンと蓮の実は地元料理に欠かせない食材で、毎年開かれる蓮祭りは、街をお祝いの気分で包み込みます。'),
  'guigang/uprising': ('金田蜂起', '1851年、桂平（けいへい）の金田村（きんでんそん）で洪秀全（こうしゅうぜん）が太平天国の乱の旗を掲げました。19世紀最大級の民衆運動はここから広がって中国の半分を揺るがし、今日、村の記念施設がその激動の時代を伝えています。'),
  'guigang/nanshan': ('南山寺', '貴港の南山寺（なんざんじ）は、石灰岩の丘の天然の洞窟に築かれた、千年の歴史を持つ聖地です。洞窟の壁には歴代王朝を通じて刻まれた碑文や詩が連なり、ひんやりとした石の堂内では、仏像たちが静かに座しています。'),
  'guigang/sugarcane': ('サトウキビ', '広西は中国の砂糖の最大の産地であり、貴港の肥沃な川沿いの平野は、その甘い生産の重要な一翼を担っています。秋にはサトウキビが人の背丈を超えて伸び、収穫の季節になると、道路は工場へキビを運ぶトラックでいっぱいになります。'),
  'yulin/medicine': ('漢方薬市場', '玉林（ぎょくりん）の薬草市場は、華南最大級の伝統薬材の交易センターです。通路には乾燥した根や樹皮、花の香りが入り混じり、商人たちは、何百年も受け継がれてきた知恵で、どの薬草の性質もそらんじています。'),
  'yulin/goldenpalace': ('雲天文化城', '雲天宮（うんてんきゅう）は、伝統的な宮殿建築を巨大なスケールで再解釈した壮麗な文化施設です。各階には精緻な彫刻、ブロンズ像、神話の場面が展示され、金色に輝く楼閣は、街のスカイラインで最も目を引く存在です。'),
  'yulin/lychee': ('ライチ園', '玉林の温暖な丘や谷は、ライチとリュウガン（竜眼）の果樹園に覆われています。初夏には枝が赤い実の房の重みでしなり、市場の屋台は甘い香りの果実であふれ、家族たちは収穫の日をお祭りのように楽しみます。'),
  'yulin/beef': ('玉林牛肉', '玉林名物の牛巴（ニウバー）は、薄切りの牛肉をスパイスの効いたタレでゆっくり乾かしながら煮て作られます。色濃く、ほのかに甘く、旨みの凝縮されたこの肉はご飯のお供やお茶請けとして親しまれ、そのレシピは家庭で代々受け継がれています。'),
  'baise/redbase': ('百色蜂起', '1929年、若き鄧小平（とうしょうへい）が指導した百色（ひゃくしょく）蜂起は、右江（ゆうこう）のほとりに革命根拠地を築きました。そのためこの街は中国の「紅色記憶」ルートの重要な訪問地となっており、記念館や旧司令部の建物が、その時代を今に伝えています。'),
  'baise/sinkhole': ('楽業天坑群', '楽業（らくぎょう）県の巨大な陥没穴「天坑（てんこう）」は、世界で最も密集した天坑群の一つを形成しています。数百メートルの深さの穴の底には手つかずの森が育ち、地下河川や洞窟のネットワークは、この地を地質学者や洞窟探検家たちの憧れの場所にしています。'),
  'baise/mango': ('マンゴーの都', '百色の暑く日差しあふれる谷は、中国で最も重要なマンゴー産地の一つです。真夏には山の斜面が黄金色に染まり、トラックが甘い果実を全国へ運びます。マンゴーは山あいの県の暮らしを支える糧であり、誇りの象徴にもなっています。'),
  'baise/aluminum': ('アルミニウムの街', '百色の山々は豊富なボーキサイト鉱床に恵まれ、この鉱石が街を中国アルミニウム産業の南の拠点にしました。鉱山と製錬所は地域経済の背骨であり、赤い大地の下に眠るこの「銀色」の金属が、何千もの家族に仕事をもたらしています。'),
  'hechi/longevity': ('巴馬の長寿村', '河池（かち）に属する巴馬（はば）は、人口に対して驚くほど多くの百歳以上の住民が暮らす、世界的に有名な「長寿の里」です。澄んだ空気、素朴な食事、あくせくしない暮らしがその秘訣とされ、毎年何千人もの人々が、健康を求めてこの谷を訪れます。'),
  'hechi/folksong': ('劉三姐', '河池の宜州（ぎしゅう）は、伝説の歌い手・劉三姐（りゅうさんじえ）のふるさととされ、チワン族の民謡の郷です。物語の中で「歌の妖精」は、即興の歌合戦で地主たちをやり込めます。この伝統は今も、歌の祭りで熱気とともに生き続けています。'),
  'hechi/bronzedrum': ('銅鼓', '銅鼓（どうこ）はチワン族やヤオ族など南方の民族にとって最も神聖な品の一つで、河池は生きた銅鼓文化の中心地とされています。浮き彫りの施された太鼓は祭りに打ち鳴らされ、その音は恵みと守護を呼ぶと信じられています。多くの村が、数百年前の太鼓を家宝のように守っています。'),
  'hechi/geopark': ('カルストジオパーク', '河池のカルスト地帯は、天坑、巨大な洞窟ホール、地下河川がそろった自然の実験室です。鳳山（ほうざん）周辺の天然の石橋や洞窟の天窓はジオパークの主役で、光が差し込む縦穴の下には、隠された世界が姿を現します。'),
  'laibin/sugarcity': ('砂糖の都', '来賓（らいひん）の平野は見渡す限りサトウキビに覆われ、この街は「中国の砂糖の都」と呼ばれています。冬の収穫が始まると工場の煙突が煙を上げ、キビから砂糖や糖蜜、紙が作られて、甘い香りが町々を包みます。'),
  'laibin/yao': ('大瑶山ヤオ族', '来賓に属する金秀（きんしゅう）の大瑶山（だいようざん）は、ヤオ族の五つの異なる支系のふるさとで、それぞれが独自の衣装、方言、儀礼を持っています。村の祭りでは銀の装身具や刺繍の頭飾りが輝き、金秀を生きた文化の博物館にしています。'),
  'laibin/hongshui': ('紅水河', '運ぶ赤い土砂からその名を得た紅水河（こうすいが）は、広西の山々を切り裂いて流れる力強い川です。谷に沿って築かれたダムは南部一帯に電力を送り、川辺の村々は、カルストの峰々の間に川が刻んだ絶景を楽しんでいます。'),
  'laibin/shengtang': ('聖堂山', '聖堂山（せいどうざん）は大瑶山脈の最高峰で、広西の屋根と呼ばれる頂の一つです。春には斜面が赤いシャクナゲで燃え立ち、頂上では雲海や日の出、風に舞う霧が、登り切った人々へのご褒美となります。'),
  'chongzuo/waterfall': ('徳天瀑布', '徳天（とくてん）瀑布は、中国とベトナムの国境を流れる川に幅広い段をなして流れ落ち、アジア最大の国境をまたぐ滝とされています。竹のいかだが水のカーテンの涼しい水しぶきへとあなたを近づけ、周囲のカルストの峰々が、景色を一幅の中国画に変えてくれます。'),
  'chongzuo/langur': ('フランソワルトン（白頭葉猴）', 'シロアタマラングールは、崇左（すうさ）の石灰岩の丘だけに生息し、世界で最も希少な霊長類の一つに数えられるサルです。夜は断崖のくぼみで眠り、昼は切り立った岩場を跳び回って過ごします。保護区のおかげで、その数は少しずつ回復しつつあります。'),
  'chongzuo/rockart': ('花山岩画', '左江（さこう）の断崖に約二千年前、駱越（らくえつ）の人々が描いた赤い人物像は、カエルのポーズで踊る何千もの人々を表しています。手の届かないはずの岩壁にどうやって描かれたのかは今も議論が続いており、この岩絵はユネスコ世界遺産に登録されています。'),
  'chongzuo/borderpass': ('友誼関', '友誼関（ゆうぎかん）は中国とベトナムを結ぶ歴史的な国境の関所で、中国の名高い関の一つに数えられます。緑の山々の間に立つアーチの楼門は、何世紀にもわたり軍隊や隊商、使節を迎えてきました。そして今日も、国境貿易の活気ある玄関口であり続けています。'),
  'beijing/great-wall': ('万里の長城', '北の国境を守るために何世紀にもわたって築かれた、全長2万キロメートルを超える世界最長の防御建造物です。北京に一番近い八達嶺(はったつれい)は、石の階段や城壁、尾根に沿って連なるのろし台を持つ、最も多くの人が訪れる区間です。'),
  'beijing/temple': ('天壇', '明と清の皇帝が毎年、豊作を天に祈った神聖な祭祀の建築群です。釘を一本も使わずに建てられた三層の丸い青屋根は、中国建築で最もよく知られたシンボルのひとつです。'),
  'beijing/pagoda': ('天寧寺塔', '遼(りょう)王朝時代に建てられた、高さ約57メートル、13層のレンガ造りの塔です。彫刻のレリーフと八角形の塔身を持つこの塔は、北京に現存する最古の建造物のひとつで、街の千年の歴史を静かに見守ってきました。'),
  'beijing/opera': ('京劇', '歌と語り、武術、アクロバットがひとつになった、200年の歴史を持つ中国の伝統舞台芸術です。役者の色鮮やかな隈取(臉譜・れんぷ)は登場人物の性格を表し、赤は忠義を、白はずる賢さを象徴しています。'),
  'zunyi/huiyi': ('遵義会議', '長征が最も苦しかった1935年、共産党の指導者たちはこの灰色の石造りの邸宅に集まり、革命の進路を描き直して毛沢東が指導者へと歩む道を開きました。現在は博物館となったこの建物のおかげで、遵義は中国の「レッドツーリズム」地図の中心に位置づけられています。'),
  'zunyi/moutai': ('茅台鎮', '赤水河のほとりにある小さな茅台鎮は、中国の国酒とたたえられる伝説の白酒マオタイのふるさとです。コーリャンから蒸留され長い年月をかけて熟成されるこの強いお酒は国家の晩餐会に欠かせない存在となり、町の空気にまで発酵の香りが漂っています。'),
  'zunyi/loushan': ('婁山関', '山々を切り裂くように険しくそびえる婁山関は、長征の途中で紅軍が歴史的な勝利を収めた戦いの舞台です。毛沢東はここで詠んだ有名な詩によってこの峠を不朽のものとし、今日訪れる人々は霧に包まれた岩場を登り、石に刻まれたその詩句を読むことができます。'),
  'zunyi/chishui': ('赤水大瀑布', '赤水では赤いタンシア（丹霞）の断崖から滝が流れ落ち、竹林と恐竜時代から生き残る巨大なヘゴが茂る谷は、まるで生きた自然博物館のようです。雨のあとに川が紅色に染まることから「赤い水」という名がつき、この景観はユネスコ世界自然遺産「中国丹霞」の一部となっています。'),
  'liupanshui/coolcity': ('涼都', '夏でも心地よい涼しさが続く高原の町、六盤水は「中国の涼しい都」という称号を誇りにしています。猛暑にあえぐ四川や重慶の人々は毎年夏になるとここへ避暑に訪れ、街はこの爽やかな気候を祭りや高原観光へと上手に生かしています。'),
  'liupanshui/coal': ('西南の炭海', '豊かな炭層の上に築かれた六盤水は、長いあいだ中国西南部のエネルギーのかまどとして働いてきました。20世紀の大規模な工業化の波の中で炭鉱と製鉄とともに成長したこの街は、今日では炭鉱都市としてのアイデンティティをグリーンエネルギーや観光と両立させようとしています。'),
  'liupanshui/grassland': ('烏蒙大草原', '雲に隣り合う烏蒙高原の果てしない草原には、馬の群れが点在し、地平線には風力タービンが並んでいます。涼しい夏の日にはイ族やミャオ族の村人たちが家畜を放牧し、高原の霧が一瞬にして立ち込めると、風景全体がおとぎの国のように変わります。'),
  'liupanshui/kiwi': ('レッドキウイ', '涼しく霧の多い高原で育つレッドハート・キウイは、六盤水の甘い緑の宝物です。中心がルビーのように赤く色づくこの果実は普通のキウイよりも甘く、収穫の季節になると山あいの村々は箱いっぱいのキウイでにぎわいます。'),
  'anshun/huangguoshu': ('黄果樹瀑布', '中国最大の滝である黄果樹瀑布は、77メートルの高さから轟音とともに流れ落ち、水しぶきの中に虹を描きます。滝の裏側にある「水簾洞」を通れば、水のカーテンの向こうから景色を眺めることができ、名作ドラマ『西遊記』のシーンもここで撮影されました。'),
  'anshun/dixi': ('地戯', '木彫りの武将の面をつけ、銅鑼の響きに合わせて村の広場で演じられる地戯は、「中国演劇の生きた化石」と呼ばれています。明代の駐屯兵とともに貴州へ伝わったこの儀礼劇は、およそ600年ものあいだ、古の戦の物語を変わらぬ熱気で語り継いできました。'),
  'anshun/batik': ('ろうけつ染め', 'プイ族やミャオ族の女性たちは溶かした蜜蝋で布に鳥や花、渦巻き模様を描き、その布を藍染めの液に浸します。蝋のひび割れに染み込んだ色が一枚一枚を唯一無二のものにするため、安順のろうけつ染めは「双子のない工芸」と呼ばれています。'),
  'anshun/tunpu': ('屯堡村落', 'およそ600年前に明の軍隊が築いた石造りの駐屯村では、屯堡の人々が今も先祖伝来の南京風の衣装をまとい、古い方言を話し続けています。石壁の路地を歩けば、時が止まった明代の町へ足を踏み入れたような気分になります。'),
  'bijie/azalea': ('百里杜鵑', '毎年春になると、畢節の山の尾根は深紅やピンク、紫のツツジで燃えるように彩られ、「百里杜鵑」は世界最大の天然ツツジ林とされています。4月の祭りの時期には、イ族やミャオ族の村人たちが花の海の中で歌をうたい、春の訪れを祝います。'),
  'bijie/zhijin': ('織金洞', '巨大な石筍と鍾乳石が森のようにそびえる織金洞は「地下の宮殿」と呼ばれ、中国で最も壮麗な鍾乳洞の一つに数えられます。大聖堂ほどの広さの空間では、「銀雨樹」のような繊細な石灰岩の造形が訪れる人を魅了します。'),
  'bijie/caohai': ('草海', '威寧高原にある浅く草の茂る草海湖は、毎年冬になると希少なオグロヅルの越冬地に変わります。朝霧が晴れるころには何千羽もの鳥の声が湖面を包み、船頭たちは葦のあいだを静かに舟で案内してくれます。'),
  'bijie/potato': ('畢節のジャガイモ', '涼しく日当たりのよい高原で育つジャガイモは、畢節を中国有数のジャガイモの穀倉地帯にしており、威寧のジャガイモは全国にその名を知られています。屋台で炭火焼きにされたり、カリッと揚げられて唐辛子をまぶされたりするジャガイモは、高原の食卓の主役です。'),
  'qujing/rapeseed': ('羅平の菜の花畑', '冬の終わりになると羅平の平野は黄金色の菜の花で埋め尽くされ、黄色い海に浮かぶ島のように立つカルストの峰々が風景に幻想的な趣を添えます。この花の海は養蜂家や写真家、蜂蜜好きを各地から引き寄せ、空気までもが甘く香ります。'),
  'qujing/ham': ('宣威ハム', '何世紀にもわたり塩漬けにされ山の空気で乾燥されてきた宣威ハムは、雲南の食卓の誇りです。バラ色の肉と深い香りによって中国で最も有名なハムの一つに数えられ、スープからお祝いの月餅まで、地元料理のあらゆる場面で使われています。'),
  'qujing/jiulong': ('九龍瀑布群', '羅平の近くでは「九龍」の名を持つ川が階段状に連なる滝を作り、一つ一つの滝が異なる幅と表情を持っています。水量の豊かな季節に黄金色の菜の花畑と重なるその景色は、中国で最も美しい滝の連なりの一つとされています。'),
  'qujing/sandforest': ('彩色沙林', '陸良のカラフル砂林では、風と雨が刻んだ砂の柱が黄金色から赤茶色、白から紫まで、さまざまな色合いに輝いています。光によって色を変えるこの天然の彫刻庭園は、映画の撮影隊や写真家たちに愛される舞台となっています。'),
  'yuxi/fuxian': ('撫仙湖', '中国で最も深い湖の一つである撫仙湖は、水晶のように澄んだ水をたたえ、雲南高原に埋め込まれた山の鏡のようです。湖底には古代の集落が沈んでいるという伝説があり、湖畔の村の漁師たちは今も名物の小魚「抗浪魚」を獲っています。'),
  'yuxi/nieer': ('聶耳', '中国国歌の作曲者である聶耳（ニエ・アル）は玉渓出身の家に生まれ、街は彼を郷土の誇りとして大切にしています。その名を冠した音楽公園や記念碑、音楽祭を通じて、玉渓は若くして世を去った作曲家の旋律を世代から世代へと受け継いでいます。'),
  'yuxi/chengjiang': ('澄江化石地', '澄江にある5億3千万年前のカンブリア紀の化石層は、動物の生命の夜明けを驚くほど細かく伝えるユネスコ世界遺産です。柔らかい組織までもが石に刻まれたこれらの生き物たちは、「カンブリア爆発」を物語る最も豊かな証人の一つです。'),
  'yuxi/kiln': ('玉渓窯', '元代にさかのぼる古い玉渓窯は、雲南の青花磁器が生まれた場所とされています。名高い景徳鎮から遠く離れた地で独自の作風を育てた地元の陶工たちは、コバルトで絵付けされた器によって中国西南部の陶磁の伝統に足跡を残しました。'),
  'dali/threepagodas': ('崇聖寺三塔', '蒼山のふもとに千年にわたってそびえる三つの優美な塔は、古代の南詔国と大理国の象徴です。幾度もの地震に耐えてきた塔は、背後の雪をいただく峰々と手前の池に映る姿とともに、大理で最も愛される絵はがきのような風景を作り出しています。'),
  'dali/erhai': ('洱海', '耳のような形からその名がついた洱海は、蒼山と大理平野のあいだに横たわる高原の湖です。白壁のペー族の村々が湖岸を彩り、自転車で湖を一周したり、日の出とともに漁船を眺めたりすることは、大理の定番の楽しみとなっています。'),
  'dali/cangshan': ('蒼山', '十九の峰とそのあいだを流れ落ちる十八の渓流を持つ蒼山は、大理の背後に緑のカーテンのようにそびえています。中国語で大理石が文字どおり「大理の石」と呼ばれるのはここに由来し、この山の岩脈から切り出される模様の美しい石は、何世紀にもわたって宮殿や寺院を飾ってきました。'),
  'dali/wind': ('風花雪月', '下関の風、上関の花、蒼山の雪、そして洱海の月――大理の四つの美「風花雪月」は、一編の詩のように語り継がれています。ペー族の女性の頭飾りにもこの四つの象徴が織り込まれており、街は自らの自然をこれほど優雅な言葉で言い表しているのです。'),
  'lijiang/oldtown': ('麗江古城', '水路と石畳の路地、瓦屋根の木造家屋が織りなす麗江古城は、ナシ族文化の生きた中心地です。城壁を持たないことで知られるこのユネスコ世界遺産の街は、かつて茶馬古道の隊商をもてなした宿場であり、今もどの路地を歩いても水の流れる音がついてきます。'),
  'lijiang/snowmountain': ('玉龍雪山', '標高5,596メートルの氷河をいただく玉龍雪山は、眠る龍のように麗江の上に輝いています。ナシ族はこの山を聖なるものとしてあがめており、ロープウェイが観光客を氷河公園へと運ぶ一方、ふもとの藍月谷はターコイズブルーの池で訪れる人を魅了します。'),
  'lijiang/dongba': ('トンパ文字', 'ナシ族の祭司たちが用いる絵文字トンパ文字は、世界で今も使われている唯一の象形文字とされています。何千冊もの写本には自然の精霊にささげる儀式やナシ族の宇宙観が記されており、この貴重な文書群はユネスコの「世界の記憶」に登録されています。'),
  'lijiang/tigerleaping': ('虎跳峡', '伝説によれば、一頭の虎が金沙江の最も狭い場所をひと跳びで越えたといい、峡谷の名はこの物語に由来します。玉龍雪山とハバ雪山のあいだに深く切れ込むこの峡谷は世界で最も深い峡谷の一つに数えられ、斜面沿いの高地トレイルはトレッカーたちの憧れです。'),
  'lincang/dianhong': ('滇紅', '鳳慶で作られる金色の芽を持つ紅茶、滇紅（デンホン）は前世紀に生まれた若いお茶でありながら、瞬く間に雲南の名を世界に知らしめました。蜂蜜とキャラメルを思わせる味わいで中国で最も評価の高い紅茶の一つに数えられ、古茶樹の葉がその味に格別の深みを与えています。'),
  'lincang/wadrum': ('ワ族の木鼓', 'ワ族は木鼓を神聖なものとしており、伝説ではその音が天と人とをつなぐ架け橋になるといわれています。滄源の山あいの村々では、女性たちが長い髪を振り乱して踊る木鼓の踊りが、収穫の日や祭りの日に谷じゅうを轟音で満たします。'),
  'lincang/teatrees': ('古茶樹', '臨滄の霧深い山々には、樹齢が数百年、時には千年をも超える野生や古来の茶樹が息づいており、お茶が生まれた森がここに守られています。春の収穫期には村人たちがはしごで巨木に登り、この古い葉から世界で最も珍重されるプーアル茶が作られます。'),
  'lincang/lancang': ('瀾滄江', 'メコン川の上流にあたる瀾滄江は、チベットから流れ下り、臨滄の深い谷を刻みながら南の東南アジアへと向かいます。川沿いに連なるダムが地域に電力を灯し、岸辺の斜面には茶畑と熱帯の果樹園が段々に広がっています。'),
  'puer/tea': ('プーアル茶', 'この山あいの街の名を冠した緊圧茶、プーアル茶は、年月を重ねるほどまろやかに熟成し価値を増す生きた宝物です。ケーキのような円盤状に固められた茶葉は数十年も保存でき、かつてはラバの隊商がこの茶餅を山越えでチベットや宮廷へと運びました。'),
  'puer/coffee': ('中国のコーヒーの都', '中国のコーヒーの大部分は普洱の霧深い斜面に広がるアラビカ農園で育っており、お茶の都は意外にもラテの香りに包まれています。コーヒー農園では試飲ツアーが開かれ、若いバリスタたちは地元の豆を世界の舞台へ送り出そうと励んでいます。'),
  'puer/teahorse': ('茶馬古道', 'ラバの隊商が茶をチベットへ運び、帰りに馬を中国へ連れ帰った古の茶馬古道は、普洱から始まり雲に包まれた峠へと登っていきました。石畳の隊商路の跡や古い宿場町は、その過酷な交易の記憶を今も生き生きと伝えています。'),
  'puer/peafowl': ('インドクジャク', '普洱周辺の熱帯林は、中国で最も希少な鳥の一つであるマクジャクの最後の楽園の一つです。この地の保護区は、この壮麗な鳥だけでなく野生のゾウやテナガザルの住みかにもなっており、街はお茶と同じくらい森を誇りにしています。'),
  'baoshan/volcano': ('騰衝火山群', '騰衝の平野には97もの休火山の火口丘が連なり、月面を思わせる風景を作り出しています。訪れる人は火口の縁まで登ったり、熱気球で火山の上を漂ったりでき、黒い溶岩石は町の家々の壁にまで使われています。'),
  'baoshan/rehai': ('熱海', '騰衝の「熱海」と呼ばれる谷では間欠泉が湯気を上げ、沸き立つ池が音を立てており、最も有名なのは巨大な「大滾鍋（大煮え鍋）」です。訪れる人は温泉の蒸気で蒸した卵を味わったあと、ミネラル豊富な湯につかり、この火山の大地の癒やしを求めます。'),
  'baoshan/heshun': ('和順古鎮', '何世紀にもわたりビルマやその先まで交易に出かけた商人たちの石造りの町、和順では、稼いだ富が優雅な邸宅や学校となって故郷に還ってきました。中国最古級の村の図書館を擁するこの町は、蓮池や石橋とともに穏やかな空気を漂わせています。'),
  'baoshan/gaoligong': ('高黎貢山', 'ミャンマー国境に沿って連なる高黎貢山は、蝶の舞う谷や温暖な森、何千種もの植物を擁する生命の宝庫です。熱帯の谷から雪の尾根へと駆け上がるこの山々は、テナガザルから滅多に見られない鳥まで、数え切れない希少な生き物たちのすみかとなっています。'),
  'deyang/sanxingdui': ('三星堆遺跡', '1986年に発見された祭祀坑から出土した、目が飛び出した巨大な青銅の仮面は、3,000年前の謎に満ちた古蜀文明を白日の下にさらしました。黄金の杖や神聖な青銅の神樹に満ちた三星堆は、中国考古学の最大の驚きの一つに数えられています。'),
  'deyang/jiannanchun': ('剣南春', '綿竹で醸される剣南春は、唐の宮廷に献上された銘酒の中にその名が記される由緒ある白酒です。途切れることなく使われ続けてきた古い発酵窖と花のような香りによって、四川の酒造りの伝統の中でも最も名誉ある名前の一つに数えられています。'),
  'deyang/nianhua': ('綿竹年画', '綿竹の手彩色の木版年画は、門番の神様やふくよかな赤ちゃん、豊かさの象徴といった縁起物を戸口に飾ります。中国の代表的な年画の伝統の一つに数えられるこの芸術では、職人が最後に施す生き生きとした筆づかいが、一枚一枚を独自の作品へと変えています。'),
  'deyang/turbine': ('重工業の都', '中国の巨大なタービンや発電機、発電所設備のかなりの部分が、徳陽の広大な工場で鍛え上げられています。「重機械の都」とされるこの街は、中国のエネルギーインフラを静かに支える鋼鉄の筋肉の一つなのです。'),
  'mianyang/libai': ('李白の故郷', '詩仙と呼ばれる李白は、少年時代を江油の山々の中で過ごし、月光と酒にささげられたその詩はここで芽生えました。彼の名を冠した記念館と博物館には、この伝説的な唐の詩人の足跡をたどろうと、毎年詩を愛する人々が集まります。'),
  'mianyang/sciencecity': ('科学城', '中国で唯一「科学技術城」の公式な称号を持つ綿陽は、研究所と電子工場によって未来を築いています。長虹（チャンホン）テレビの故郷でもあるこの街は、白衣をまとった、四川で最も「賢い」顔といえるでしょう。'),
  'mianyang/qiang': ('羌族の石楼', '北川の山村では、チャン族の石造りの物見やぐらが何世紀ものあいだ立ち続けており、巧みに積み上げられたこれらの塔は防御と威信の両方の象徴でした。白い石への信仰と羊毛の刺繍を守り続けるチャン族の村々は、いにしえの山岳文化を今に伝えています。'),
  'mianyang/mifen': ('綿陽米粉', '鶏や牛、モツのだしで湯気を立てる細い米麺（ミーフェン）が、早朝の綿陽を目覚めさせます。極細の麺はほんの数秒でゆで上がり、カウンターで丼に顔を寄せる人々の列は、この街の最も変わらぬ朝の風物詩です。'),
  'nanchong/langzhong': ('閬中古城', '風水の理にかなって築かれた、最も保存状態のよい古城の一つである閬中は、嘉陵江の湾曲に抱かれるように眠っています。漢代の天文学者・落下閎の故郷として「中国の春節文化のふるさと」とされ、酢の香り漂う路地には明・清時代の街並みが今も残っています。'),
  'nanchong/silk': ('シルクの都', '2,000年を超える養蚕と織物の伝統を持つ南充は、中国西部のシルクの都という称号を担っています。かつてシルクロードに絹を供給したこの街は、今も製糸工場やシルク博物館とともに生き、その光沢のある絹織物は世界の市場へと旅立っています。'),
  'nanchong/zhangfei': ('張飛牛肉', '三国志の英雄・張飛は長年にわたり閬中に駐屯し、その廟は今もこの街に立っています。外は真っ黒、中はバラ色をしたスパイスの効いた干し牛肉「張飛牛肉」は、英雄の「黒い顔」のイメージにちなんで名づけられた、遊び心のある名物です。'),
  'nanchong/zhude': ('朱徳の故郷', '人民解放軍の創設者の一人である朱徳元帥は、儀隴の貧しい農家に生まれました。質素な生家と記念館は現代中国史の巡礼地の一つとなっており、訪れる人はここでつつましい出発点が持つ力を感じ取ることができます。'),
  'yibin/wuliangye': ('五糧液', 'コーリャン、米、もち米、小麦、トウモロコシから蒸留される五糧液は、この「五つの穀物」からその名を取り、中国で最も高く評価される白酒ブランドの一つです。宜賓の湿潤な気候と何百年も使われ続けてきた発酵窖が、この酒に独特の重層的な香りを与えています。'),
  'yibin/firstcity': ('長江第一城', '岷江と金沙江が合流する地点から、川は長江という名を持つようになります。だからこそ宜賓は「万里の長江、第一の城」と呼ばれるのです。色の異なる二つの流れが出会う岬は今では川辺の公園となり、街が誇る象徴的な風景になっています。'),
  'yibin/bamboosea': ('蜀南竹海', '百を超える丘を覆う蜀南竹海は、風に波打つ果てしない緑の海です。竹林の涼しい小道、隠れた滝、タケノコを使った郷土料理が訪れる人を包み込み、映画の撮影隊もこの緑の世界をたびたび舞台に選んでいます。'),
  'yibin/ranmian': ('燃麺', 'ほとんど水を使わずにこね、香り高い油をたっぷりと和えた「燃麺（ランミエン）」は、油に火がつくほど乾いていることから「燃える麺」という名を得ました。唐辛子と花椒、炒ったピーナッツをまとったこの麺は、宜賓の朝ごはんの目の覚めるような主役です。'),
  'luzhou/laojiao': ('瀘州老窖', '1573年から途切れることなく使われ続けている泥の発酵窖は、瀘州の「濃香型」白酒の伝統の心臓部です。窖に生きる微生物の文化は代々受け継がれており、蒸留の名人たちは、最も古い窖こそが酒に最も深い香りを与えると信じています。'),
  'luzhou/port': ('長江港', '沱江が長江に注ぐ場所に築かれた瀘州は、四川が海へと開く水の玄関口です。その埠頭からは何世紀にもわたって塩や酒、穀物が積み出され、今日でもコンテナ港が内陸の各省を長江下流域と世界へつないでいます。'),
  'luzhou/longan': ('リュウガン（竜眼）', '「龍の眼」と呼ばれる蜂蜜のように甘い小さな果実、リュウガンは、瀘州の川沿いの温暖な斜面で育ちます。この街は中国で最も北に位置する大規模なリュウガン果樹園のいくつかを擁しており、遅く熟すこの果実は秋になると市場の屋台に山と積まれます。'),
  'luzhou/umbrella': ('分水油紙傘', '分水の職人たちが手作りする油紙傘は、竹の骨組みと手描きの絵柄を持つ、400年の歴史を誇る優雅な工芸品です。数十もの工程を経て仕上げられる一本一本の傘は、雨だけでなく幸運にも開かれます。その丸い形は円満と幸福の象徴なのです。'),
  'leshan/giantbuddha': ('楽山大仏', '断崖に彫られた高さ71メートルの座仏は、三つの川が激しくぶつかり合う合流点を1,200年ものあいだ静かに見守ってきました。唐代の僧・海通が行き交う船を守るために始めたこの壮大な事業は、今ではユネスコ世界遺産となっており、その足の指の上だけでも数十人が立てるほどの大きさです。'),
  'leshan/emei': ('峨眉山', '仏教の四大名山の一つである峨眉山は、雲海の上に輝く金頂で巡礼者やハイカーたちを招いています。登山道は古い寺院のかたわらを縫うように続き、運のよい日には山頂で「仏光」と呼ばれる環状の虹を見ることができます。'),
  'leshan/monkeys': ('峨眉山のサル', '峨眉山の登山道に暮らすいたずら好きのマカクザルたちは、巡礼者のかばんを堂々と探ることで有名です。地元の人々は彼らを「山の主人」と呼び、手すりに寝そべって写真のポーズをとるサルたちは、山旅の最も楽しい――そして最もやんちゃな――思い出を残してくれます。'),
  'leshan/qiaojiao': ('翹脚牛肉', '薬草や香辛料とともに何時間も煮込まれる牛肉スープ「蹺脚（チャオジャオ）牛肉」は、かつて客が高い腰掛けに足をのせながらスープをすすったことからその名がつきました。およそ100年にわたり楽山の街角の定番であるこの湯気の立つ一杯は、モツでさえもごちそうに変えてしまいます。'),
  'zigong/saltwell': ('深海井', '約2,000年にわたり塩井とともに生きてきた自貢では、竹のロープを使った掘削技術が燊海井（しんかいせい）で頂点に達しました。世界で初めて深さ1,000メートルを超えた井戸がここで掘られたのです。木造のやぐらと塩業博物館が、この「塩の都」の知恵を物語っています。'),
  'zigong/lantern': ('自貢灯会', '毎年新年の季節になると、自貢は巨大な光の灯籠の庭が広がるおとぎの国に変わります。龍や宮殿、物語の主人公たちが絹と鋼でそびえ立ち、この街の灯籠職人たちは今や世界各地の都市でもこの光の祭典を作り上げています。'),
  'zigong/dinosaur': ('自貢恐竜博物館', '大山鋪のジュラ紀の地層からあふれ出た何千もの化石は、自貢を中国の恐竜の都にしています。発掘現場の真上に建てられた博物館では骨の層が発見されたままの姿で展示され、そびえ立つ竜脚類の骨格が訪れる人をジュラ紀の奥深くへといざないます。'),
  'zigong/rabbit': ('冷兎', 'ラー油と花椒、ピーナッツで和えて冷たいまま供されるウサギ肉「冷吃兎（ロンチートゥ）」は、四川で最も大胆な前菜の一つで、そのふるさとは自貢です。塩業労働者たちの力のつく食卓から生まれたこの街の料理は、スパイスを惜しまない伝統を今日まで守り続けています。'),
  'panzhihua/steel': ('バナジウム・チタンの都', '金沙江の山あいの谷に築かれた攀枝花は、世界で最も豊かなバナジウム・チタン鉱床を操業する巨大な鉄鋼都市です。20世紀の大工業化の波の中でゼロから立ち上がったこの街の名は、この地方特有のカポックの木（パンジーホワ）の燃えるような赤い花に由来しています。'),
  'panzhihua/fruitvalley': ('陽光果物谷', '乾燥して暑い金沙江の谷では、太陽の恵み豊かなこの微気候の中で、マンゴーやザクロ、バナナが冬に入るまで熟していきます。晩生のマンゴーは街の誇りであり、果樹園は鉄鋼の街に思いがけないほど熱帯的な味わいを添えています。'),
  'panzhihua/sunshine': ('冬の陽光都市', '年間およそ2,700時間もの日照に恵まれる攀枝花は、暖かく明るい冬を求める人々の保養の地です。北国の寒さから逃れてきた退職者たちは冬の季節をここで過ごし、街はその太陽の恵みをスポーツ合宿や温泉リゾートで飾っています。'),
  'panzhihua/jinsha': ('金沙江', '「金色の砂の川」を意味する金沙江は、長江の上流として深い谷を刻みながら、攀枝花の真ん中を勢いよく流れていきます。川沿いの水力発電ダムが地域に電力を供給し、橋や川辺の遊歩道がその岸辺に活気を与えています。'),
  'dazhou/gas': ('天然ガスの都', '達州の地下には中国最大級の天然ガス田である普光ガス田が広がっており、この街を国のエネルギー基地の一つにしています。パイプラインはここから東部の工業都市へと延び、ガス経済は山がちな四川のこの一角に新しい時代を開きました。'),
  'dazhou/ba': ('巴国の遺産', 'ここは柳の葉の形をした剣で知られる古代の巴人の戦士たちの土地であり、虎の紋章を持つ彼らの青銅器は羅家壩遺跡で静かに語りかけてきます。川の谷に生きたこの戦う民の謎めいた文化は、四川の歴史の最も古い地層の一つを形づくっています。'),
  'dazhou/dengying': ('灯影牛肉', '光が透けるほど薄く切ってスパイスをまぶした「灯影（デンイン）牛肉」は、ランプの明かりで演じられた影絵芝居にちなんで名づけられました。紙のように薄くパリッとした肉片は甘辛い香辛料をまとい、達州のこの上品なおつまみは100年以上にわたって食卓を彩ってきました。'),
  'dazhou/hanque': ('漢闕', '渠県の野に立ち続ける2,000年前の石造りの「闕（けつ）」の塔は、今日まで残る漢代建築のまれな優美さを伝えるものです。かつて墓への参道を飾ったこれらの彫刻された門塔は、伝説の霊獣や日々の暮らしの場面によって、漢の世界を石に刻み込んでいます。'),
  'guangyuan/jianmen': ('剣門関', '「一人が守れば万人も通れぬ」といわれる剣門関は、剣の刃のように切り立つ断崖を持つ、古代の蜀の道の要の関所です。三国時代からずっと軍勢がせめぎ合う要衝であったこの峠は、李白の「蜀道の難きは青天に上るよりも難し」という詩句を思い起こさせます。'),
  'guangyuan/wuzetian': ('武則天の生誕地', '中国史上ただ一人の女帝である武則天は広元に生まれたと信じられており、皇沢寺は千年にわたって彼女をまつってきました。街は毎年、女性の祭りでこの偉大な女帝を祝い、川辺の寺院にはその像が静かに座しています。'),
  'guangyuan/plankroad': ('古桟道', '断崖に打ち込んだ梁の上に木の板を渡した桟道は、「天に登るより難しい」といわれた蜀の道を通行可能にした、勇気の記念碑です。明月峡には古の桟道の跡が今も残っており、訪れる人は復元された板の道を歩きながら、かつての隊商の胸の高鳴りを感じることができます。'),
  'guangyuan/cypress': ('翠雲廊', '古道の両側に立ち並ぶ何万本もの老イトスギが、翠雲廊を緑のトンネルへと変えています。伝説では、その植樹の一部は三国志の英雄・張飛の命によるものとされ、この木陰の道は世界で最も古くから守られてきた並木道の一つに数えられています。'),
  'yaan/panda': ('パンダの故郷', 'ジャイアントパンダが初めて学術的に世界へ紹介されたのは1869年、宝興でのことでした。フランスの博物学者アルマン・ダヴィドの報告が、この愛らしい動物を世界に知らしめたのです。碧峰峡のパンダ基地がその遺産を受け継いでおり、雅安の霧深い竹林はパンダのふるさとであり続けています。'),
  'yaan/rain': ('雨の街', '「雅の雨」はほとんど毎晩のように屋根を洗い、朝になると街は洗い立ての緑の千の色合いに輝きます。地元の人々は三つの美――雅の雨、雅の魚、雅の乙女――を数え上げ、この三つが雨の街の優しく豊かな心を言い表しています。'),
  'yaan/mengding': ('蒙頂山茶', '言い伝えによれば、お茶が初めて人の手で植えられたのは約2,000年前の蒙頂山であり、この山はそのため茶文化のゆりかごとされています。山頂の古い茶園の葉は何世紀にもわたって皇帝に献上され、霧に包まれた斜面では今日も茶の儀式が行われています。'),
  'yaan/yayu': ('雅魚', '雪解け水の流れる渓流で育つ伝説の雅魚は、ぐつぐつと煮立つ土鍋料理として食卓に上り、この街の三つの美の一つに数えられています。引き締まった白身で名高いこの魚の頭には剣の形をした小さな骨が隠れており、地元の伝説はこの「剣」をめぐってさまざまな物語を紡いできました。'),
  'xianyang/qincapital': ('秦の都', 'ここは中国を初めて統一した秦王朝の都であり、始皇帝は咸陽から帝国への道を歩みました。宮殿のあった場所は今では遺跡となり、博物館の青銅器や宮殿の礎石が、2,000年以上前の権勢を静かにささやいています。'),
  'xianyang/qianling': ('乾陵', '武則天と夫の高宗皇帝が山を掘って合葬された乾陵は、盗掘されずに今日まで残る数少ない唐代の陵墓の一つです。参道には石の守護像や外国使節の像が並び、武則天が立てさせた文字のない「無字碑」は、自らの評価を歴史に委ねています。'),
  'xianyang/zhengguo': ('鄭国渠', '戦国時代の末期に開かれた鄭国渠は、関中平野を潤して秦の穀倉地帯へと変え、天下統一の経済的な土台を築きました。2,000年以上にわたってこの地域を養い続けてきたこの水利システムは、古代の土木技術の天才的な傑作といえます。'),
  'xianyang/guokui': ('鍋魁', '鍋のふたほど大きくて分厚く、カリッとした平焼きパン「鍋盔（グオクイ）」は、陝西名物の「十大不思議」の一つに数えられています。薪の火でじっくりと焼かれるこのパンは何日ももち、その由来は、兵士たちがかぶとの中で焼いたという昔の遠征の言い伝えにまでさかのぼります。'),
  'baoji/bronze': ('青銅器の都', '周王朝の中心地であった宝鶏の大地からは、銘文を刻んだ青銅器が何千点も出土しており、その中の「何尊」には「中国（中國）」という名の現存最古の記述が残されています。この街の青銅器博物館は、3,000年前の匠の技を世界屈指の豊かなコレクションで展示しています。'),
  'baoji/famen': ('法門寺', '仏陀の指の骨の舎利を守る法門寺は、唐の皇帝たちの聖なる宝物庫でした。1987年に塔の下の隠された地下宮殿が開かれると、金銀や絹からなるまばゆい唐の秘宝が姿を現し、今日では壮大な伽藍がこの舎利をまつっています。'),
  'baoji/taibai': ('太白山', '秦嶺山脈の屋根ともいえる標高3,771メートルの太白山は、夏になっても消えない雪で数々の伝説を生み、「太白の六月の雪」は古の関中の名高い景色の一つでした。氷河湖へと続く登山道は、中国の北と南を分ける自然の境界線そのものの上を歩かせてくれます。'),
  'baoji/saozi': ('臊子麺', '酸味と辛味のある肉のたれをかけた岐山の「臊子麺（サオズめん）」は、細く長くコシのある麺で、周代の料理の生きた味とされています。酢と揚げ唐辛子の踊るような味わいにニンジンや卵、キクラゲが寄り添い、結婚式で客に何杯もふるまうのは何百年も続く習わしです。'),
};
